INSERT INTO public.photos VALUES (23194, 'El Pilar 2010', 'Foto: Rusolera, agosto de 2010. Remoce de las torres del Pilar que dan al Ebro, como culmen de la â”œâ•‘ltima reforma de la basâ”œآ،lica. Fuente: zaragozaciudad.net/zaragozafluye/2014/010101-boira.php', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494946720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494946720.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494946720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23218, 'Fin de fiestas 2018', 'Imagen capturada desde el puente de Hierro durante el tradicional broche a las Fiestas del Pilar del aâ”œâ–’o 2018, protagonizado por el espectâ”œأ­culo pirotâ”œآ®cnico que el domingo 14 de octubre y desde la Arboleda de Macanaz iluminâ”œâ”‚ el ribereâ”œâ–’o cielo ante decenas de miles de personas congregadas a pesar de unas previsiones meteorolâ”œâ”‚gicas poco propicias, que finalmente no se cumplieron. La empresa Pirotecnia Zaragozana se encarga de estos actos desde 1860, cuando los cohetes se lanzaban desde el Coso y la plaza de la Constituciâ”œâ”‚n. En la imagen, los fuegos se imponen sobre el râ”œآ،o Ebro y el puente de Piedra.', 2018, 2018, 2018, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65891700, -0.87845500, '0101000020E6100000EA3E00A94D1CECBFA4E36A6457D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50315056737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50315056737.webp', 'https://www.flickr.com/photos/zaragozaantigua/50315056737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23231, 'El Pilar 2030', 'Ilustraciâ”œâ”‚n de cubierta para el câ”œâ”‚mic "Pilar Ultimate" (2010), con guion de Jorge Asâ”œآ،n y dibujos de Moratha. Representa el entorno del Pilar y el Ebro en el aâ”œâ–’o 2030, aâ”œâ–’o en el que se activan misteriosamente las bombas guardadas en el interior del templo. En el centro, un alienâ”œآ،gena surge de la silueta de la Virgen del Pilar; a la derecha, una comandante de la "Interestelar Civil Guard". Fuente: moratha.blogspot.com', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65684300, -0.87862700, '0101000020E6100000323ECC5EB61DECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40095343121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40095343121.webp', 'https://www.flickr.com/photos/zaragozaantigua/40095343121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23794, 'Vista del este 1930', 'Antâ”œâ”‚nio Passaporte no era un luso al uso, y dijo que para capturar una imagen, cuanto mâ”œأ­s arriba, mejor. Y si habâ”œآ،a que sacar brillo a una titulada "El Ebro y vista parcial", desde los 90 metros de altura de la torre de Santiago en el templo del Pilar, el panorama serâ”œآ،a de lujo. Dicho y hecho, aquâ”œآ، queda el testimonio del râ”œآ،o, sus dos riberas (la derecha, especialmente), y una vista parcial del "barrio de La Seo" y del Casco Histâ”œâ”‚rico: la plaza de La Seo, y la plaza del Pilar. A la derecha, la torre de la Magdalena, tal y como estaba rematada por entonces. Esto fue antes del Plan de Reforma Interior de 1939, que desbaratâ”œâ”‚ bastante unos aâ”œâ–’os despuâ”œآ®s todo esto. Este Plan fue ideado para que el "despegue hacia la modernidad" no encontrara obstâ”œأ­culos urbanâ”œآ،sticos en la "ciudad histâ”œâ”‚rica", reiterando los argumentos que desde mediados del siglo XIX se esgrimâ”œآ،an en muchas ciudades europeas: insalubridad, falta de condiciones higiâ”œآ®nicas y, signo de los tiempos, abrir hueco al trâ”œأ­fico rodado, que mira que no haber pensado en ello... Y todo generando notables plusvalâ”œآ،as econâ”œâ”‚micas, por supuesto, que acabaron en los bolsillos de algunas personas, de cuyo nombre es mejor no acordarse.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65680900, -0.87930800, '0101000020E6100000B08EE3874A23ECBFF75B3B5112D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850702434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850702434.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850702434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23799, 'El Pilar 1860', '"Zaragoza : Templo de Nuestras Seâ”œâ–’ora del Pilar". Una de las fotos mâ”œأ­s antiguas del Pilar, con la inacabada torre de Santiago, la câ”œâ•‘pula del Coro, el arranque de la câ”œâ•‘pula central antes de ser recrecida unos aâ”œâ–’os despuâ”œآ®s, y la câ”œâ•‘pula de la Santa Capilla rodeada de cuatro câ”œâ•‘pulas menores. Fuente visual: Charles Clifford, en Biblioteca Nacional de Espaâ”œâ–’a', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65758000, -0.87901200, '0101000020E6100000655419C6DD20ECBF7940D9942BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14917839470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14917839470.webp', 'https://www.flickr.com/photos/zaragozaantigua/14917839470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23801, 'Plaza del Pilar 1967', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 30/11/1967. "Fiesta de la Policâ”œآ،a Armada en la Plaza del Pilar." Mâ”œأ­s que fiesta, fiestorro nacional-catâ”œâ”‚lico-militarista. Imagen de la plaza del Pilar con la gris revista de los policâ”œآ،as armados, a pie, y a equino. Al fondo, San Juan de los Panetes y por encima de la alargada sombra de los cipreses, la alargada sombra del instrumento de tortura romano que seâ”œâ–’ala el monumento a quienes ganaron la guerra 1936-1939. Una guerra que tuvo sus vencedores. Vaya que si los tuvo.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65663300, -0.87934600, '0101000020E610000010CAFB389A23ECBFB83CD68C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15079575658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15079575658.webp', 'https://www.flickr.com/photos/zaragozaantigua/15079575658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23806, 'Plaza del Pilar c.1941', 'Taxis en las traseras del Pilar. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.11 Carpeta 23863', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65665700, -0.87922800, '0101000020E6100000954737C2A222ECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295762328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295762328.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295762328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23808, 'El Pilar 1968', 'Vista aâ”œآ®rea de la plaza del Pilar y el râ”œآ،o Ebro en 1968. Fuente: www.facebook.com/photo.php?fbid=10203073944866386&set...', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65674300, -0.87849300, '0101000020E61000004A7A185A9D1CECBF3F70952710D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15386061880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15386061880.webp', 'https://www.flickr.com/photos/zaragozaantigua/15386061880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23810, 'El Pilar 1987', 'Luis Mâ”œآ،nguez. 1987. El trâ”œأ­nsito del 1986 al 1987 trajo nieve, momento que captura esta imagen tomada, al natural, desde la torre de San Francisco de Borja, hacia la ribera derecha del Ebro, con visual de la nieve posada en câ”œâ•‘pulas, cupulillas y tejados de la ciudad. En las torres y câ”œâ•‘pulas del Pilar permanecen las jaculatorias luminosas instaladas a principios de los aâ”œâ–’os cincuenta, cuando se instalaron luces de neâ”œâ”‚n en los remates de la basâ”œآ،lica que reproducâ”œآ،an la estâ”œâ”‚lida jaculatoria dedicada a la Virgen del Pilar (â”¬آ½Bendita y alabada sea la hora en que Marâ”œآ،a Santâ”œآ،sima vino en carne mortal a Zaragoza. Por siempre sea bendita y alabadaâ”¬â•—), versos entonados por las voces del Coro de Infantes del Pilar y emitidos desde 1940, por atronadora megafonâ”œآ،a exterior, cada dâ”œآ،a a las 09.00, a las 12.00 y a las 20.00h. Las jaculatorias visuales se retiraron, aâ”œâ–’os despuâ”œآ®s. Las otras, perduran.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65727900, -0.87893800, '0101000020E6100000D2C5A6954220ECBF7EACE0B721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15643746208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15643746208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15643746208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23811, 'El Pilar 1907', '"Vue d''ensemble de Notre-Dame du Pilier", Lucien Roy, 1907. Desde el Puente de Piedra, imagen del templo del Pilar con la segunda torre ya terminada, pendiente sâ”œâ”‚lo de retirar el andamiaje de obra, y algunos de los edificios de la ribera (la Casa de los Infantes, el Palacio de los Marqueses de Ayerbe). El poste metâ”œأ­lico seâ”œâ–’ala el lugar de paso del tranvâ”œآ،a de la lâ”œآ،nea de Circunvalaciâ”œâ”‚n, ya electrificada. Siguen pasando vehâ”œآ،culos a tracciâ”œâ”‚n de sangre. Fuente: Sociâ”œآ®tâ”œآ® Franâ”œآ؛aise d''Archâ”œآ®ologie et Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine - diffusion RMN', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15662709823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15662709823.webp', 'https://www.flickr.com/photos/zaragozaantigua/15662709823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23816, 'El Pilar mudâ”œآ®jar 1668', 'El acta notarial levantada en 1668 con motivo de la demoliciâ”œâ”‚n del templo mudâ”œآ®jar del Pilar es una detallada descripciâ”œâ”‚n del edificio que existâ”œآ،a antes del actual templo barroco-clasicista. Su aspecto exterior serâ”œآ،a muy similar a las iglesias de Santiago de Montalbâ”œأ­n, y San Pedro de Teruel: en ladrillo, una â”œâ•‘nica nave, capillas laterales entre los gruesos contrafuertes, coro a los pies, poderosa torre, entrada por la fachada sur (la de la plaza), y un claustro cuadrangular anexo en el lado del Ebro con capillas laterales en dos de sus lados, y la Santa Capilla en su centro. En la imagen, vista desde la ribera del Ebro de la reconstrucciâ”œâ”‚n virtual del exterior (iglesia y claustro), separadas por un "muro antiguo de la ciudad", tal vez un paâ”œâ–’o de la antigua muralla romana. El 25 de julio de 1681 fue colocada la primera piedra del nuevo templo, y en 1718 estaba concluida la mitad occidental. Se procediâ”œâ”‚ entonces al traslado al nuevo altar mayor del Santâ”œآ،simo Sacramento, procediâ”œآ®ndose inmediatamente al piqueteo de la anterior iglesia mudâ”œآ®jar y el viejo claustro, al objeto de continuar las obras en la parte oriental del nuevo templo. Fuente: "La reconstrucciâ”œâ”‚n virtual del Pilar mudâ”œآ®jar. Bases histâ”œâ”‚ricas y potencial didâ”œأ­ctico", Mâ”¬آ¬ Pilar Rivero, IFC, 2014.', 1668, 1668, 1668, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16078379708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16078379708.webp', 'https://www.flickr.com/photos/zaragozaantigua/16078379708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23820, 'Zaragoza 1844', '"Templo del Pilar", una vista desde la margen izquierda, en la arboleda de Macanaz. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•‌edades y vistas pintorescas en lâ”œأ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œآ® Marâ”œآ،a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65888300, -0.87877900, '0101000020E6100000B22B2D23F51EECBFF871344756D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18936497886.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18936497886.webp', 'https://www.flickr.com/photos/zaragozaantigua/18936497886/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23825, 'Plaza del Pilar 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”œآ®rea de la plaza del Pilar de Zaragoza en 1988. Fuente: Aragâ”œâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20309642472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20309642472.webp', 'https://www.flickr.com/photos/zaragozaantigua/20309642472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23827, 'Templo del Pilar 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 40, Zaragoza 1908 - Centenario de los Sitios", 1907. "Los aragoneses pelearon por amor a su Virgen tanto como por amor a su patria. Armâ”œأ­banse de valor ante el altar de su Patrona y despuâ”œآ®s de cada triunfo entonaban ante ella solemnes alabanzas. Los ancianos y los niâ”œâ–’os refugiâ”œأ­banse allâ”œآ، durante los bombardeos, instalando sus camas junto al tabernâ”œأ­culo. No obstante, en distintas ocasiones las bombas francesas perforaron las torres y las bâ”œâ”‚vedas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20779959321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20779959321.webp', 'https://www.flickr.com/photos/zaragozaantigua/20779959321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23828, 'Mallorca y Zaragoza 1490', 'Detalle de una sarga (tela pintada) representando milagros de la Virgen del Pilar. Maestro de Luesia, sacristâ”œآ،a mayor del Pilar, 1490. La imagen narra la peripecia de un rico matrimonio de Palma de Mallorca que rezaba a la Virgen del Pilar para tener hijos. Cuando les nace un varâ”œâ”‚n, deciden ir a Zaragoza para agradecer el favor. Durante el viaje, pierden al niâ”œâ–’o cuando cae del barco. Pese a todo, van al camarâ”œآ،n dentro del claustro subterrâ”œأ­neo del Pilar, y allâ”œآ، estâ”œأ­, a los pies de la Virgen, su hijo vivo, que les cuenta que fue ella quien le salvâ”œâ”‚ y le llevâ”œâ”‚ hasta allâ”œآ،. Como limosna, entregan un arca de plata. A la izquierda, Palma de Mallorca; en el centro, momento en el que el niâ”œâ–’o cae de cabeza al mar; a la derecha, Zaragoza, con el hijo seâ”œâ–’alando a la Virgen. Sobre â”œآ®sta vemos los arcos del claustro del Pilar mudâ”œآ®jar, en su â”œâ•‘nica representaciâ”œâ”‚n conocida. Fuente: "El milagro de Calanda y otros favores extraordinarios de Nuestra Seâ”œâ–’ora del Pilar", Tomâ”œأ­s Domingo y Ester Casorrâ”œأ­n, ed. Comuniter, 2015.', 1490, 1490, 1490, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65689500, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF5F3A62215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20949846723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20949846723.webp', 'https://www.flickr.com/photos/zaragozaantigua/20949846723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23833, 'Vista aâ”œآ®rea 1954', 'Vista aâ”œآ®rea del centro de Zaragoza en 1954. Fuente: AMZ, a travâ”œآ®s de www.facebook.com/photo.php?fbid=10203685974269714&set...', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22298695011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22298695011.webp', 'https://www.flickr.com/photos/zaragozaantigua/22298695011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23834, 'Vista aâ”œآ®rea Ebro 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea desde el este de Zaragoza del râ”œآ،o Ebro a su paso por la ciudad. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22304117552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22304117552.webp', 'https://www.flickr.com/photos/zaragozaantigua/22304117552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23844, 'El Pilar 1904', 'Vista del templo del Pilar desde la ribera del Ebro en una imagen publicada en 1904, con la torre de Santiago (1715) ya recrecida. Fuente: Revista "La fiesta nacional", Barcelona, 1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24457587551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24457587551.webp', 'https://www.flickr.com/photos/zaragozaantigua/24457587551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23855, 'El Pilar c.1904', 'Cromolitografâ”œآ،a editada por el librero local Cecilio Gasca para su colecciâ”œâ”‚n de imâ”œأ­genes titulada "Aragâ”œâ”‚n", e impresa por Purger & Co. (Mâ”œâ•‌nchen) como tintada postal que captura la tâ”œآ،pica fachada al râ”œآ،o Ebro del templo metropolitano de El Pilar, en los pocos aâ”œâ–’os que mediaron entre la finalizaciâ”œâ”‚n del remate de la primera torre, y la erecciâ”œâ”‚n de la segunda. Fuente visual: www.delcampe.net/', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65684800, -0.87858500, '0101000020E61000007632384A5E1DECBFB438639813D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27251156345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27251156345.webp', 'https://www.flickr.com/photos/zaragozaantigua/27251156345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23857, 'Ministros negros 1940', 'Dentro del oficial y grandioso centenario diecinueve del fantâ”œأ­stico empadronamiento de la virgen del Pilar en la ciudad, allâ”œأ­ por el aâ”œâ–’o 40 de la era, un evento fue remarcadamente seâ”œâ–’alado por las crâ”œâ”‚nicas locales: la devota consagraciâ”œâ”‚n en el metropolitano del Pilar, en ceremonia conducida por el obispo de la colonia de Guinea Espaâ”œâ–’ola, de tres nuevos ministros del seâ”œâ–’or, con la exâ”œâ”‚tica particularidad de pertenecer a la "raza negra", indâ”œآ،gena de esta colonia, lo que fue significado como "la mejor prueba de la fecunda labor misional que Espaâ”œâ–’a practica en aquellas regiones africanas, llevâ”œأ­ndoles la luz de la Fe". Ante el altar mayor pilarista, de espaldas, arrodillados y deslumbrados, los tres nuevos ministros negros del seâ”œâ–’or. Fuente visual: Miguel Marâ”œآ،n Chivite, revista "Aragâ”œâ”‚n".', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65692700, -0.87845700, '0101000020E61000001827BEDA511CECBF016E162F16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27450646770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27450646770.webp', 'https://www.flickr.com/photos/zaragozaantigua/27450646770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23859, 'El Pilar 1861', 'Foto del templo del Pilar desde la margen izquierda del Ebro, cuando todavâ”œآ،a no tenâ”œآ،a ni câ”œâ•‘pula central ni la primera torre terminada. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey, Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65692700, -0.87845700, '0101000020E61000001827BEDA511CECBF016E162F16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28490108971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28490108971.webp', 'https://www.flickr.com/photos/zaragozaantigua/28490108971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23864, 'Elâ”œآ®ctricas Reunidas 1966', 'Acciâ”œâ”‚n de 500 pesetas de Elâ”œآ®ctricas Reunidas de Zaragoza, que comienza su actividad en 1911, al unirse varias industrias del sector. Entre 1952 y 1965, su presidente fue Josâ”œآ® Sinuâ”œآ®s, tambiâ”œآ®n al frente de la Caja de Ahorros de Zaragoza. Estas dos entidades formaron parte del mismo conglomerado durante todo el siglo XX. En los aâ”œâ–’os 70 y 80, ERZ era la empresa con mayor volumen de facturaciâ”œâ”‚n en Aragâ”œâ”‚n. En 1999 es absorbida por el grupo Endesa, propiedad de una multinacional italiana. Encabezando el documento, una reproducciâ”œâ”‚n del templo del Pilar. Fuente visual: www.ebay.es', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65685900, -0.87856700, '0101000020E6100000DD088B8A381DECBFA88AA9F413D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30167115373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30167115373.webp', 'https://www.flickr.com/photos/zaragozaantigua/30167115373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23872, 'Congreso Esperanto 1954', 'Cartel de la 15â”¬آ¬ Hispana Kongreso de Esperanto, celebrado en Zaragoza en julio de 1954. Incluye la estrella verde esperantista, el escudo de la ciudad y una vista del Pilar y el puente de Piedra. Fuente: www.bildarchivaustria.at/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65690700, -0.87858800, '0101000020E6100000BB0ED594641DECBFB9C1508715D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30871684811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30871684811.webp', 'https://www.flickr.com/photos/zaragozaantigua/30871684811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23874, 'Sindicato de Iniciativa 1929', 'Cartel del Sindicato de Iniciativa y Propaganda de Aragâ”œâ”‚n, representando una vista del Pilar desde la Seo, impreso en Litografâ”œآ،a Portabella y diseâ”œâ–’ado por â”œأ«mile Paul Champseix. Esta entidad se constituyâ”œâ”‚ como asociaciâ”œâ”‚n en 1925, para promover el turismo de la regiâ”œâ”‚n. Hasta 1936, tambiâ”œآ®n es una fuerza de influencia polâ”œآ،tica regeneracionista y regionalista. Fuente: Revista Aragâ”œâ”‚n Turâ”œآ،stico y Monumental, junio de 2015.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65676300, -0.87848100, '0101000020E61000003909A52F841CECBF861C5BCF10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30931050553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30931050553.webp', 'https://www.flickr.com/photos/zaragozaantigua/30931050553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23877, 'Coronaciâ”œâ”‚n canâ”œâ”‚nica 1905', '"Peregrinaciâ”œâ”‚n y solemne coronaciâ”œâ”‚n a N. Sâ”¬آ¬ del Pilar". Medalla diseâ”œâ–’ada por el escultor Carlos Palao y acuâ”œâ–’ada por los hermanos Faci, en el marco de la coronaciâ”œâ”‚n canâ”œâ”‚nica de la Virgen del Pilar, celebrada el 20 de mayo de 1905, que incluyâ”œâ”‚ celebraciones y una peregrinaciâ”œâ”‚n, entre el 19 de mayo y el 18 de junio. En el anverso se representa a Isabel la Catâ”œâ”‚lica, vestida de peregrina y representando a Espaâ”œâ–’a, postrada ante Zaragoza, que la recibe con el Pilar de fondo. En el reverso, estandarte insignia de la peregrinaciâ”œâ”‚n, con la Virgen del Pilar sobre el escudo del papa Pâ”œآ،o X. Fuente visual: www.milanuncios.com', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65690700, -0.87854500, '0101000020E6100000E90E62670A1DECBFB9C1508715D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31012227463.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31012227463.webp', 'https://www.flickr.com/photos/zaragozaantigua/31012227463/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23878, 'Guâ”œآ،a de Zaragoza 1928', 'Guâ”œآ،a Oficial de Zaragoza 1928-1929. Sindicato de Iniciativa y Propaganda de Aragâ”œâ”‚n, 1928. Folleto turâ”œآ،stico de reparto gratuito. La cubierta a color, firmada por Codin Hnos., representa las fiestas del Pilar, con la basâ”œآ،lica deconstruida al fondo. Fuente: www.todocoleccion.net', 1928, 1928, 1928, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65692300, -0.87850200, '0101000020E6100000170FEF39B01CECBFBF7E880D16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31016396351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31016396351.webp', 'https://www.flickr.com/photos/zaragozaantigua/31016396351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23880, 'El Pilar 1954', 'Fantâ”œأ­stica composiciâ”œâ”‚n empleada como recuerdo del Congreso Mariano del aâ”œâ–’o 1954, celebrado con ocasiâ”œâ”‚n del Centenario I del dogma catâ”œâ”‚lico de la Inmaculada (o Purâ”œآ،sima) Concepciâ”œâ”‚n. Un descomunal Papa Pâ”œآ،o XII, iluminado por la Virgen del Pilar, abre los brazos ante las multitudes que acuden a la basâ”œآ،lica concatedral, fulminantemente recrecida en las dos torres recayentes a la ribera del Ebro. Dos fuentes gigantes refrescan la plaza, aun siendo octubre, cuya despejada perspectiva parece llegar hasta la plaza de Sas (antigua del Carbâ”œâ”‚n). Fuente visual: www.ebay.es/', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65681400, -0.87852200, '0101000020E6100000DE205A2BDA1CECBF08C72C7B12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31302905426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31302905426.webp', 'https://www.flickr.com/photos/zaragozaantigua/31302905426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23886, 'Coronaciâ”œâ”‚n Canâ”œâ”‚nica 1905', '"Medalla Oficial de la Coronaciâ”œâ”‚n de Ntra. Sra. del Pilar de Zaragoza". Agustâ”œآ،n Querol, 1905. En el anverso, la Santâ”œآ،sima Trinidad coronando a la Virgen con la propia corona canâ”œâ”‚nica, con el escudo de Zaragoza abajo a la izquierda. En el reverso, la Virgen acompaâ”œâ–’ada de â”œأ­ngeles que cantan la jaculatoria "Bendita y alabada sea", y una representaciâ”œâ”‚n del puente de Piedra y el templo del Pilar. La coronaciâ”œâ”‚n canâ”œâ”‚nica de la Virgen del Pilar, celebrada el 20 de mayo de 1905, incluyâ”œâ”‚ celebraciones y una peregrinaciâ”œâ”‚n, entre el 19 de mayo y el 18 de junio. Fuente visual: www.todocoleccion.net', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65689100, -0.87852400, '0101000020E61000000B09185DDE1CECBFB404190115D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32046219460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32046219460.webp', 'https://www.flickr.com/photos/zaragozaantigua/32046219460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23887, 'Cincomarzada aâ”œâ–’os 30', 'Foto: Miguel Marâ”œآ،n Chivite. Grupo de personas celebrando la Cincomarzada en la arboleda de Macanaz, un 5 de marzo de los aâ”œâ–’os treinta. Al fondo, el Pilar. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65936000, -0.87948900, '0101000020E6100000C422861DC624ECBF312592E865D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32129094301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32129094301.webp', 'https://www.flickr.com/photos/zaragozaantigua/32129094301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23888, 'La novia del cierzo 1983', 'Segunda de las tres viâ”œâ–’etas dibujadas por Isidro Ferrer para el relato "La novia del Cierzo". En la ilustraciâ”œâ”‚n, Cierzo se cala el cachirulo y sopla sobre su novia, la ciudad de Zaragoza. Doâ”œâ–’a Niebla tiene que irse, por mâ”œأ­s que se agarra a las torres del Pilar. Un ciudadano con paraguas vuela acongojado. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1983, 1983, 1983, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65684300, -0.87861000, '0101000020E6100000AF08FEB7921DECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32148478516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32148478516.webp', 'https://www.flickr.com/photos/zaragozaantigua/32148478516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23892, 'Vista aâ”œآ®rea Pilar c.1968', 'Vista aâ”œآ®rea centrada el el Pilar, con el barrio de Jesâ”œâ•‘s al fondo. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65684300, -0.87852400, '0101000020E61000000B09185DDE1CECBFA3CD716E13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33697981745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33697981745.webp', 'https://www.flickr.com/photos/zaragozaantigua/33697981745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23894, 'El Pilar 1955', 'Con motivo de los fastos en torno al centenario diecinueve de la venida de la Virgen del Pilar en carne mortal a Zaragoza (1940), el pintor valenciano Ramâ”œâ”‚n Stolz Viciano fue encargado para restaurar las bâ”œâ”‚vedas iluminadas in illo tempore por Goya, Bayeu y Gonzâ”œأ­lez Velâ”œأ­zquez. El resultado satisfizo a la Junta de Obras y al Cabildo catedralicio, de modo que le encargaron pintar despuâ”œآ®s la bâ”œâ”‚veda del Coro Mayor con una alegorâ”œآ،a mural de "La Mâ”œâ•‘sica al servicio de la Divinidad" (1941). En 1952 recibiâ”œâ”‚ un nuevo llamado para pintar dos pequeâ”œâ–’os murales, el patriâ”œâ”‚tico "La rendiciâ”œâ”‚n de Granada" y el antropolâ”œâ”‚gico "El milagro de Calanda", y en 1955 fue requerido para iluminar la elâ”œآ،ptica câ”œâ•‘pula sobre el ingreso al Coro Mayor con el motivo "Regina Sacratissimi Rosarii", mediante la representaciâ”œâ”‚n de una solemne procesiâ”œâ”‚n del Rosario, por lo que esta câ”œâ•‘pula desde entonces suele ser denominada la câ”œâ•‘pula del Rosario. Para la realizaciâ”œâ”‚n de esta encomienda contâ”œâ”‚ con el refuerzo del pintor catalâ”œأ­n Josâ”œآ® Alfonso Cunâ”œآ، y su compaâ”œâ–’era Alicia Bravo, que son quienes aparecen en la imagen, sobre el andamiaje dispuesto para poder acceder a la altura del lienzo mural. Fuente visual: www.josecuni.eu/', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65696500, -0.87874300, '0101000020E610000080D8D2A3A91EECBFEECEDA6D17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35003474481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35003474481.webp', 'https://www.flickr.com/photos/zaragozaantigua/35003474481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23910, 'El Pilar 1778', 'Ilustraciâ”œâ”‚n contemporâ”œأ­nea (1948) del templo del Pilar que hubiera resultado de hacerse segâ”œâ•‘n el proyecto de Ventura Rodrâ”œآ،guez, irrealizado en buena parte. Destaca la vistosa soluciâ”œâ”‚n dada a la fachada del Coreto, a la izquierda, y el remate de las cuatro torres "bajas" de las esquinas. La presencia de las câ”œâ•‘pulas y cupulillas resulta anacrâ”œâ”‚nica, ya que fueron levantadas a mediados del siglo XIX. Tambiâ”œآ®n lo es la ausencia de la manzana de viviendas que desde el Retiro Bajo y vertebrada por la calle del Pilar llegaba hasta la Puerta del â”œأ¼ngel. Es lo que tiene hacer un dibujo cuando toda esa manzana habâ”œآ،a sido derribada al comienzo de la dâ”œآ®cada de los aâ”œâ–’os 40 del siglo XX para levantar sobre su solar la nueva Casa Consistorial.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65697800, -0.87856200, '0101000020E61000006B44300E2E1DECBF8318E8DA17D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52526464307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52526464307.webp', 'https://www.flickr.com/photos/zaragozaantigua/52526464307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24212, 'Ferrocarril de Canfranc 1933', '"Ferrocarril de Canfranc a Valencia por Zaragoza. Medio siglo de constancia aragonesa. 1882-1933. Del continente al Mediterrâ”œأ­neo por Aragâ”œâ”‚n y Valencia". Medalla conmemorativa de las cinco dâ”œآ®cadas transcurridas desde el inicio de las obras del tren transpirenaico por Canfranc. La estaciâ”œâ”‚n internacional habâ”œآ،a sido inaugurada en 1928, y la lâ”œآ،nea fue clausurada en 1970, convirtiendo su reapertura en una reivindicaciâ”œâ”‚n que permanece durante otro medio siglo. En el anverso, una locomotora de vapor. En el reverso, el monolito situado en la frontera franco-espaâ”œâ–’ola del puerto de Somport, levantado en 1862; el Miguelete o torre campanario de la catedral de Valencia; y el Pilar de Zaragoza, tras el puente de Piedra. Fuente visual: www.todocoleccion.net', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65685900, -0.87858400, '0101000020E6100000603E59315C1DECBFA88AA9F413D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38806332944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38806332944.webp', 'https://www.flickr.com/photos/zaragozaantigua/38806332944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24228, 'Ferias y fiestas 1882', 'Portada de una Guâ”œآ،a de ferias y fiestas en Zaragoza de 1882, con reproducciâ”œâ”‚n de la Torre Nueva (derribada diez aâ”œâ–’os despuâ”œآ®s), la estatua de Ramâ”œâ”‚n Pignatelli (notablemente adelgazado), el Puente de Piedra y el Pilar, y unos cabezudos. Fuente: Gigantes y Cabezudos en Aragâ”œâ”‚n, Ibercaja, 1990.', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65700500, -0.87865200, '0101000020E61000006A1492CCEA1DECBF7C2766BD18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23643795533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23643795533.webp', 'https://www.flickr.com/photos/zaragozaantigua/23643795533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24237, 'Fiestas del Pilar 1934', '"De mi pueblo", cartel de las Fiestas del Pilar de 1934, obra de Guillermo Pâ”œآ®rez Baylo. Al fondo, el puente del piedra y el Pilar. Se le atribuye un modernismo tardâ”œآ،o. Lo que sâ”œآ، es evidente es el uso de los colores de la bandera de la Repâ”œâ•‘blica en la figura principal. Fuente visual: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87858800, '0101000020E6100000BB0ED594641DECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32515670212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32515670212.webp', 'https://www.flickr.com/photos/zaragozaantigua/32515670212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24732, 'Vista de la Margen Izquierda 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. Vistas de la Margen Izquierda desde la torre de San Francisco de Borja del Pilar.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65723400, -0.87880400, '0101000020E6100000EB01F390291FECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817000907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817000907.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817000907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24737, 'Fuente de la Princesa aâ”œâ–’os 30', '"Durante algo menos de 10 aâ”œâ–’os, la Fuente de la Princesa que estuvo antes en la actual Plaza de Espaâ”œâ–’a, fue montada con mâ”œأ­s pena que gloria en la Arboleda de Macanaz de Zaragoza. La fuente no llegâ”œâ”‚ nunca a echar agua por sus caâ”œâ–’os. Miraba al Pilar hasta que fue trasladada al actual Parque Grande Josâ”œآ® Antonio Labordeta." Mâ”œأ­s informaciâ”œâ”‚n: tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne... Fuente: somoszaragoza.wordpress.com/2011/08/31/fuente-de-la-princ...', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65907800, -0.87886200, '0101000020E6100000124F7633A31FECBFADC1FBAA5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180429201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180429201.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180429201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24766, 'Arboleda de Macanaz 1930', 'Foto: Archivo Heraldo de Aragâ”œâ”‚n. Rebaâ”œâ–’o de cabras con un grupo de personas en la orilla del Ebro, junto a la arboleda de Macanaz. Al fondo, el puente de Piedra. Fuente: www.facebook.com/photo.php?fbid=838460819509878&set=g...', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20708117216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20708117216.webp', 'https://www.flickr.com/photos/zaragozaantigua/20708117216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24767, 'Arboleda de Macanaz 1865', 'Plano de la arboleda de Macanaz, Antonio Berbegal, Zaragoza, 1865. Al norte, el camino de Ranillas. Al sur, el râ”œآ،o Ebro. Se distingue el arbolado mediante distintos colores. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65942800, -0.87907900, '0101000020E6100000593673486A21ECBF8908FF2268D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21033348365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21033348365.webp', 'https://www.flickr.com/photos/zaragozaantigua/21033348365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25060, 'La Pilar de Potosâ”œآ، 1954', '1954. La "Hermandad de Campeadores Hispâ”œأ­nicos" entregâ”œâ”‚ una imagen de la Virgen del Pilar a la Iglesia de Santiago del Râ”œآ،o, en la mejicana ciudad de San Luis de Potosâ”œآ،. El acto se hizo en el Monasterio de San Lorenzo de El Escorial. Se trataba de una talla del siglo XVII que pertenecâ”œآ،a al periodista Emilio Alfaro, director de "La Hoja del Lunes de Zaragoza", que la entregâ”œâ”‚ para ser regalada. El Ayuntamiento de Zaragoza la vistiâ”œâ”‚ con el manto de la ciudad, sin coste aâ”œâ–’adido (lo pagâ”œâ”‚ la ciudad). Improvisada imagen de grupo, con el donante Emilio Alfaro (al fondo), la donada (en el centro), el receptor mejicano Francisco Salazar Hernâ”œأ­ndez (izquierda), y el intermediario sacerdote indâ”œآ،gena Alfonso D. Ruiz (derecha).', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65675300, -0.87845000, '0101000020E6100000787AA52C431CECBF6346787B10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14923345181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14923345181.webp', 'https://www.flickr.com/photos/zaragozaantigua/14923345181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25076, 'Sofâ”œآ،a y Elena 1970', 'Foto: Luis Mompel. Sofâ”œآ،a de Grecia sostiene a su hija Elena de Borbâ”œâ”‚n en el camarâ”œآ،n de la Virgen del Pilar de Zaragoza, en 1970. Segâ”œâ•‘n rumor popular, el acceso de adultos a ese espacio estâ”œأ­ vedado, con excepciones como la de Francisco Franco y esta seâ”œâ–’ora, que en la â”œآ®poca formaba parte de su corte. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65689500, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF5F3A62215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21404068478.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21404068478.webp', 'https://www.flickr.com/photos/zaragozaantigua/21404068478/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25118, 'El Pilar 1976', 'Carlos Azagra. 1976. Colaboraciâ”œâ”‚n de Carlos Azagra para el Boletâ”œآ،n de la "Asociaciâ”œâ”‚n de Cabezas de Familia" del Barrio de San Josâ”œآ®. La basâ”œآ،lica del Pilar como montaje con que los poderes econâ”œâ”‚micos, sociales y religioso-militares pretenden ocultar la realidad de una ciudad que echa humo.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65668300, -0.87844600, '0101000020E61000001DAA29C93A1CECBF6A6B44300ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15183105342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15183105342.webp', 'https://www.flickr.com/photos/zaragozaantigua/15183105342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25163, 'Arboleda de Macanaz c.1943', '"Paisaje". â”œأ´leo sobre lienzo, Rafael Aguado Arnal, c.1940-1945. Representaciâ”œâ”‚n de la arboleda de Macanaz, con el puente de Piedra al fondo. Fuente: web.dpz.es/arscatalogi.es', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65891100, -0.87854500, '0101000020E6100000E90E62670A1DECBFC2FC153257D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32118617263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32118617263.webp', 'https://www.flickr.com/photos/zaragozaantigua/32118617263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25171, 'El Pilar 1978', 'Ilustraciâ”œâ”‚n de Antonio Soteras publicada en el tercer y â”œâ•‘ltimo nâ”œâ•‘mero de la revista del Colectivo Zeta (1978). Muestra una metâ”œأ­fora visual crâ”œآ،tica con la sociedad zaragozana de la â”œآ®poca. Con el templo del Pilar al fondo, un obrero custodiado por dos policâ”œآ،as armados sostiene a la Virgen, que nutre a un burguâ”œآ®s acomodado y a una baturra que representa las adocenadas fiestas locales. Este dibujo, variante de la tradicional iconografâ”œآ،a de la pirâ”œأ­mide social, asâ”œآ، como una fotografâ”œآ،a en la contraportada que recuerda la â”œأœltima Cena, fueron motivo de denuncia, que desembocâ”œâ”‚ en un juicio por escarnio a la religiâ”œâ”‚n catâ”œâ”‚lica al aâ”œâ–’o siguiente. La sentencia fue de cuatro aâ”œâ–’os de câ”œأ­rcel. Mâ”œأ­s informaciâ”œâ”‚n: www.zaragozarebelde.org/zeta-la-ultima-letra Fuente visual: Colecciâ”œâ”‚n particular de Antonio Altarriba.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33868573636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33868573636.webp', 'https://www.flickr.com/photos/zaragozaantigua/33868573636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25521, 'El Pilar c.1864', 'Imagen parcial de una placa estereoscâ”œâ”‚pica capturada desde la margen izquierda del râ”œآ،o Ebro, y centrada en el Templo Metropolitano de Nuestra Seâ”œâ–’ora del Pilar, caracterizado exteriormente por la inacabada torre de Santiago, y cubierto por la câ”œâ•‘pula del Coro, el arranque de la câ”œâ•‘pula central, y la câ”œâ•‘pula de la Santa Capilla rodeada de cuatro câ”œâ•‘pulas menores. Si bien esta es una de las escasas imâ”œأ­genes del Pilar antes de las obras de construcciâ”œâ”‚n de la gran câ”œâ•‘pula central, y de las cuatro câ”œâ•‘pulas que rodean al Coro, tal vez el valor aâ”œâ–’adido mâ”œأ­s estimable aquâ”œآ، sea una pequeâ”œâ–’a vista lateral de la ribereâ”œâ–’a Puerta del â”œأ¼ngel, que desde el puente de Piedra abrâ”œآ،a el acceso a la ciudad por la calle de la Lonja, entre el Seminario Episcopal y la Casa del Ayuntamiento. Esta imagen, en una versiâ”œâ”‚n completa que se extiende por el puente de Piedra, e incluye la torre de Santiago del Pilar, fue luego incluida en el libro de viajes por Espaâ”œâ–’a de Edmondo De Amicis, realizado durante el reinado de Amadeo I de Saboya. Fuente visual: original de Ferrier et Soulier editada por J. Lâ”œآ®vy et Câ”œآ،a, en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œآ،a profesional y comercial 1850-1970, PUZ.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34598416160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34598416160.webp', 'https://www.flickr.com/photos/zaragozaantigua/34598416160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25533, 'Vista del Ebro c.1863', '"Zaragoza. Vista del Ebro." Minimalista e irrepetible imagen del pretil que delimitaba la ribera y el paseo del Ebro, capturada desde leve altura en la zona de la antigua puerta y calle del Fin, durante una de las primeras visitas de Jean Laurent a la ciudad. En la margen izquierda, pasado el râ”œآ،o, la arboleda de Macanaz y el desemboque de la acequia de desagâ”œâ•‌e de las Balsas de Ebro Viejo. Fuente visual: Archivo Ruiz-Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico) www.mcu.es', 1863, 1863, 1863, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870679830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870679830.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870679830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25541, 'El Ebro y el Pilar 1958', 'Foto Manuel Coyne, 1958. Vista aâ”œآ®rea del râ”œآ،o Ebro a su paso por Zaragoza y de la plaza del Pilar y su entorno. Fuente: "El colegio notarial de Aragâ”œâ”‚n", 2007.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20356542108.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20356542108.webp', 'https://www.flickr.com/photos/zaragozaantigua/20356542108/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25545, 'Vista aâ”œآ®rea Ebro 1959', 'Vista aâ”œآ®rea del paso del râ”œآ،o Ebro por Zaragoza, desde la desembocadura del râ”œآ،o Gâ”œأ­llego hasta el barrio de San Pablo. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65687900, -0.87860700, '0101000020E61000006B2C616D8C1DECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22302370502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22302370502.webp', 'https://www.flickr.com/photos/zaragozaantigua/22302370502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
