INSERT INTO public.photos VALUES (23766, 'Acampo de Funes 2001', 'Ortofoto del Acampo de Funes, terrenos del tâ”œآ®rmino municipal de Zaragoza entre Torrecilla de Valmadrid y La Cartuja (que se ve a la derecha). En la parte inferior de la imagen se observa la construcciâ”œâ”‚n del polâ”œآ،gono industrial Empresarium. La prâ”œأ­ctica totalidad del resto del encuadre estâ”œأ­ hoy ocupada por las gigantescas instalaciones del Parque Tecnolâ”œâ”‚gico de Reciclado Lâ”œâ”‚pez Soriano, ubicadas ahâ”œآ، desde 2002. Fuente visual: www.nacionrotonda.com/', 2001, 2001, 2001, 'Siglo XXI', NULL, 41.58616400, -0.83677100, '0101000020E61000000BB8E7F9D3C6EABFD80B056C07CB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25538479172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25538479172.webp', 'https://www.flickr.com/photos/zaragozaantigua/25538479172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25569, 'Arboleda de Macanaz c.1959', 'Imagen capturada desde la arboleda de Macanaz y centrada en una entraâ”œâ–’able, tipista y folklâ”œâ”‚rica estampa con el fondo del râ”œآ،o Ebro y el Pilar. Resulta de interâ”œآ®s el aspecto de la torre del noroeste del templo metropolitano en construcciâ”œâ”‚n, denominada de San Francisco de Borja, y luego con carâ”œأ­cter popular "la del ascensor". Al otro lado de la calle de Florencio Jardiel, antigua del Retiro Alto, vista del progreso edilicio en la manzana nâ”¬â•‘ 6 de la nueva plaza del Pilar, con las traseras de la Hospederâ”œآ،a del Pilar recayente a la plaza, y de los talleres y naves habilitados para el modelado y talla de las esculturas instaladas en la fachada meridional del templo durante las obras de rehabilitaciâ”œâ”‚n del templo acometidas en la segunda mitad de los aâ”œâ–’os cuarenta y primeros aâ”œâ–’os cincuenta. Estas provisionales construcciones fueron derribadas luego para dar paso a las Casas del Cabildo y el nuevo Colegio de los Infantes.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65890100, -0.87884100, '0101000020E610000034492C29771FECBF9E2633DE56D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48347636107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48347636107.webp', 'https://www.flickr.com/photos/zaragozaantigua/48347636107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25992, 'El Pilar en obras 1945', 'Vista aâ”œآ®rea del Pilar durante la restauraciâ”œâ”‚n de la fachada principal en 1945. Fuente visual de la imagen: Colecciâ”œâ”‚n Luis Ariza, en rafaelcastillejo.com', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20085860653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20085860653.webp', 'https://www.flickr.com/photos/zaragozaantigua/20085860653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26053, 'Zaragoza 1899', '"Caesaraugusta". Ilustraciâ”œâ”‚n de Francisco de Paula Albiâ”œâ–’ana (Tarragona, 1841). Fuente: Revista Nuevo Mundo, 1899.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65679000, -0.87853200, '0101000020E6100000C1A90F24EF1CECBF802BD9B111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32233525914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32233525914.webp', 'https://www.flickr.com/photos/zaragozaantigua/32233525914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21066, 'Plaza del Pilar c.1877', 'Archivo Ruiz-Vernacci. Jean Laurent. Ca. 1874-1877 Zaragoza. La iglesia de Nuestra Seâ”œâ–’ora del Pilar, vista desde la plaza. Fuente visual: www.mcu.es/fototeca_patrimonio/ImageServlet?accion=41&...', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16059629682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16059629682.webp', 'https://www.flickr.com/photos/zaragozaantigua/16059629682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21084, 'El Pilar 1877', 'Desde mediados del siglo XIX, las grandes familias de la ciudad acometieron su particular revoluciâ”œâ”‚n burguesa, conservadora, a la zaragozana, y el espacio urbano fue tambiâ”œآ®n modificado al efecto. Asâ”œآ،, se impulsâ”œâ”‚ la urbanizaciâ”œâ”‚n del Salâ”œâ”‚n de Santa Engracia, y se fomentâ”œâ”‚ una especial fijaciâ”œâ”‚n por la transformaciâ”œâ”‚n urbana de la ciudad vieja abriendo rectos viales y ordenando las manzanas de forma regular, especialmente allâ”œآ، donde la operaciâ”œâ”‚n estaba asociada a un buen beneficio econâ”œâ”‚mico privado. La ampliaciâ”œâ”‚n de la calle de Don Jaime I, por ejemplo. El nomenclâ”œأ­tor de la ciudad tambiâ”œآ®n fue objeto de una importante mutaciâ”œâ”‚n, eliminando nombres de toda la vida considerados ahora "vulgares", de "dudoso gusto", o "provincianos", para sustituirlos por personajes de los asedios de 1808-1809, asâ”œآ، como prâ”œâ”‚ceres y determinadas eminencias sociales. Esta local "revoluciâ”œâ”‚n" necesitaba el respaldo de un nuevo consenso social que legitimara el proceso, el orden resultante, y las estructuras sociales y econâ”œâ”‚micas a â”œآ®l asociadas. El reforzamiento de la â”œآ،ntima identificaciâ”œâ”‚n de la ciudad con el culto pilarista fue piedra angular de esta estrategia, y su impacto urbanâ”œآ،stico fue tambiâ”œآ®n notable. A la apertura de la calle de Alfonso I en 1860, le siguiâ”œâ”‚ la reforma de la plaza del Pilar dos aâ”œâ–’os despuâ”œآ®s, y en 1864 se iniciâ”œâ”‚ la construcciâ”œâ”‚n de la gran câ”œâ•‘pula central pilarista, terminada en 1872. Los inicios del siglo XX verâ”œآ،an nacer y desarrollarse otros interesantes proyectos que reforzaron esta tendencia: el proyecto de la gran plaza del Pilar, iniciado a finales de la dâ”œآ®cada de los aâ”œâ–’os treinta, planea ya en 1905. Esta fenomenal captura de Jean Laurent y Câ”¬آ¬, realizada en altura, desde un solanar a medio camino entre la calle de los Convertidos y la de Alfonso I, ilustra la nueva plaza del Pilar resultante de la reforma de 1862, con sus â”œأ­rboles, fuentes, bancos, y quioscos, la reciente y prominente gran câ”œâ•‘pula central, y el estado del templo, con su inacabada y barroca torre de Santiago, ', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65627400, -0.87954800, '0101000020E61000000264E8D84125ECBF899B53C900D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28735376946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28735376946.webp', 'https://www.flickr.com/photos/zaragozaantigua/28735376946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21116, 'Plaza del Pilar c.1880', 'Temprana imagen, desde cierta altura, de la antigua plaza del Pilar, cuando el templo metropolitano mantenâ”œآ،a la â”œâ•‘nica torre realizada del proyecto original. Fuente visual: Estudio Coyne (Archivo Municipal de Zaragoza/DARA)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26261388624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26261388624.webp', 'https://www.flickr.com/photos/zaragozaantigua/26261388624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21123, 'Plaza del Pilar 1889', 'Imagen de la antigua plaza del Pilar capturada desde la rinconera con la calle de Damiâ”œأ­n Forment, cuando el templo metropolitano mantenâ”œآ،a la â”œâ•‘nica e inacabada torre de Santiago del barroco proyecto original. A la derecha, acceso, o retiro, bajo, hacia la ribera o paseo del Ebro.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65606100, -0.87808200, '0101000020E6100000C899266C3F19ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34262340196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34262340196.webp', 'https://www.flickr.com/photos/zaragozaantigua/34262340196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21130, 'Pl. del Pilar c.1880', 'Luminosa imagen parcial capturada en la antigua plaza del Pilar resultante de la reforma que en 1862 le confiriâ”œâ”‚ este aspecto de recoleto espacio arbolado con bancos, farolas y quioscos que en invierno, como es el caso, era frecuentado como monumental y tranquila solanera. A la izquierda, la antigua casa de los Aytona. En la parca fachada original del templo metropolitano despunta la â”œâ•‘nica e incompleta torre de Santiago levantada a principios del siglo XVIII.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65636500, -0.87891900, '0101000020E610000022A81ABD1A20ECBF999EB0C403D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41577698185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41577698185.webp', 'https://www.flickr.com/photos/zaragozaantigua/41577698185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21154, 'Plaza del Pilar 1890', 'Imagen de la plaza del Pilar, con el templo del Pilar previo a la culminaciâ”œâ”‚n del remate de la original torre de Santiago del Pilar, en 1892. Fuente visual: Revista Nuevo Mundo, octubre de 1897.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19093740076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19093740076.webp', 'https://www.flickr.com/photos/zaragozaantigua/19093740076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21192, 'Plaza del Pilar c.1890', 'Imagen capturada en la plaza del Pilar y centrada en la salida por la Puerta Baja del homâ”œâ”‚nimo templo de una procesiâ”œâ”‚n de canâ”œâ”‚nigos portando palmas durante la celebraciâ”œâ”‚n del Domingo de Ramos.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65630400, -0.87817600, '0101000020E6100000213A048E041AECBFF31DFCC401D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50122324581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50122324581.webp', 'https://www.flickr.com/photos/zaragozaantigua/50122324581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21202, 'Plaza del Pilar 1894', 'Imagen centrada en la puerta Baja del templo del Pilar antes de la salida de la tradicional procesiâ”œâ”‚n que el luminoso dâ”œآ،a 12 de octubre y en el marco de las religiosas fiestas en homenaje a la Virgen del Pilar, saliendo del homâ”œâ”‚nimo templo a las 18:00 h. recorriâ”œâ”‚ las calles de los Convertidos, Prudencio, la Virgen, Manifestaciâ”œâ”‚n, plaza del Mercado, Cerdâ”œأ­n, Coso, Don Jaime I, plaza de La Seo y regresâ”œâ”‚ a la plaza del Pilar. En la fotografâ”œآ،a se recoge, a la izquierda de la puerta, vista del farol correspondiente al primer misterio gozoso denominado أ”أ‡آ£La Anunciaciâ”œâ”‚n del Hijo de Diosأ”أ‡أک que fue diseâ”œâ–’ado por Ricardo Magdalena Tabuenca en 1890 y construido en los talleres de Leâ”œâ”‚n Quintana y Bianchi sitos en la calle del Cuatro de Agosto. Asistieron a dicha procesiâ”œâ”‚n todas las autoridades, institutos, corporaciones, hermandades y cofradâ”œآ،as de la ciudad, amâ”œآ®n de los obispos de Lugo, â”œأ¼vila, Huesca y auxiliar de Zaragoza, que acompaâ”œâ–’aron al Nuncio de Su Santidad. Presidiâ”œâ”‚ la procesiâ”œâ”‚n el Gobernador civil, acompaâ”œâ–’ado del comandante general, el alcalde y el presidente de la Audiencia provincial.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54192694198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54192694198.webp', 'https://www.flickr.com/photos/zaragozaantigua/54192694198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21286, 'Plaza del Pilar 1903', 'Imagen desde cierta altura, junto al Pasaje de la Industria y el Comercio, y la calle de Forment, de la antigua plaza del Pilar, cuando perduraba su planta barroca, recogida, acogedora, y una foresta caracterizaba su peculiar espacio interior. A la derecha, junto al ingreso de la original puerta baja del metropolitano templo, han comenzado a montarse los andamios de la obra de culminaciâ”œâ”‚n de la segunda torre, la oriental, baja, nueva, o de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, finalizada en 1907. Al fondo, el antiguo palacio de los Aytona, y el edificio de los Grandes Almacenes del Pilar. Fuente: Fototipia Lucas Escolâ”œأ­, en www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65643100, -0.87886400, '0101000020E61000003F373465A71FECBF508A56EE05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25935356943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25935356943.webp', 'https://www.flickr.com/photos/zaragozaantigua/25935356943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21290, 'Plaza del Pilar 1903', 'Imagen parcial, capturada desde el punto de vista de un turista accidental, fotâ”œâ”‚grafo "amateur", peatâ”œâ”‚n impenitente, y ademâ”œأ­s francâ”œآ®s, de la antigua plaza del Pilar, cuando perduraba su planta barroca, acogedora, y una foresta caracterizaba su peculiar y recoleto espacio interior. Situado en el â”œأ­ngulo sureste de la plaza, el cuadro de enfoque se centra en la â”œâ•‘nica torre del templo, su reciente juego de câ”œâ•‘pulas sobre el coro, y la desornamentada fachada, para que luego se diga que lo barroco es siempre sinâ”œâ”‚nimo de recargamiento innecesario: serâ”œأ­n otros, dâ”œآ®cadas despuâ”œآ®s, los que se encarguen de darle su iconâ”œâ”‚dulo aspecto "de toda la vida". Lo mismo sucederâ”œأ­ con las "tradicionales" actividades socio-lâ”œâ•‘dicas vinculadas en esta plaza con la veneraciâ”œâ”‚n de masas en sus distintos formatos: esas cosas, antes, no se hacâ”œآ،an. Son contemporâ”œأ­neas con el aire acondicionado, que estaba siendo inventado por esos primeros aâ”œâ–’os del XX, y que en los aâ”œâ–’os 50-60 empezâ”œâ”‚ a difundirse masivamente. Tal que igual. Fuente: www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26907155455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26907155455.webp', 'https://www.flickr.com/photos/zaragozaantigua/26907155455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21364, 'Plaza del Pilar 1913', 'Foto: Lorenzo Almarza. Plaza del Pilar desde la basâ”œآ،lica, con la calle Alfonso al fondo a la derecha. Fotografâ”œآ،a tomada el 15 de marzo de 1913. Fuente: Archivo Diputaciâ”œâ”‚n Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65630400, -0.87892200, '0101000020E61000006684B7072120ECBFF31DFCC401D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920293899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920293899.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920293899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21491, 'Los quioscos del Pilar 1923', 'AHPZ. Archivo fotogrâ”œأ­fico Julio Requejo. 18/03/1923. "Vista del Pilar." A la notable foresta de la plaza acompaâ”œâ–’aba una interesante cantidad de casetas o quioscos, alguno para aliviar necesidades fisiolâ”œâ”‚gicas improrrogables, otros de venta de variados productos de consumo râ”œأ­pido. Como toda plaza o espacio abierto comâ”œâ•‘n, tambiâ”œآ®n era susceptible de ser escenario de encuentros mâ”œأ­s o menos casuales entre personas de distintas orientaciones sexuales. Por eso, era normal la presencia de la "carabina" (como la de primer plano, que escolta a una seâ”œâ–’orita en el camino de acceso a la puerta principal del templo), como forma de vigilancia militante para garantizar que la decencia y moral hegemâ”œâ”‚nica no sufrâ”œآ،an quebrantos.', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65608000, -0.87845500, '0101000020E6100000EA3E00A94D1CECBFA4C7EF6DFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15218934870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15218934870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15218934870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21562, 'Plaza del Pilar c.1925', 'No son legiâ”œâ”‚n las imâ”œأ­genes de la antigua y barroca plaza del Pilar, mucho menos fotografiada que las de la fachada a la ribera del Ebro. La desnudez clasicista de su lienzo evoca al original muro de cerramiento del templo levantado a principios del siglo XVIII, en un espacio recoleto y minimal, arbolado, e integrado en la trama urbana. Luego vendrâ”œأ­ el espectâ”œأ­culo de masas. Fuente visual: Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65639900, -0.87886400, '0101000020E61000003F373465A71FECBF4510E7E104D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22525437290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22525437290.webp', 'https://www.flickr.com/photos/zaragozaantigua/22525437290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21577, 'Plaza del Pilar c.1920', 'Uno de los quioscos que flanqueaban la vâ”œآ،a de acceso a la "puerta baja" de la basâ”œآ،lica del Pilar. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24276746864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24276746864.webp', 'https://www.flickr.com/photos/zaragozaantigua/24276746864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21733, 'Gil Robles 1933', 'A finales del mes de agosto el Pilar fue escenario del enlace matrimonial entre Amalia Casanueva, hija de Câ”œأ­ndido Casanueva, diputado en Cortes por el Partido Agrario, y Josâ”œآ® Landra de Lara. Asistieron como testigos Josâ”œآ® Marâ”œآ،a Gil Robles, diputado en Cortes y referente agrarista estatal que acabada de crear la Confederaciâ”œâ”‚n Espaâ”œâ–’ola de Derechas Autâ”œâ”‚nomas (CEDA); Antonio Royo Villanova, agrarista y diputado en Cortes, al poco Ministro de Marina; y Santiago Guallar Poza, canâ”œâ”‚nigo y diputado agrarista en Cortes. Pocos dâ”œآ،as despuâ”œآ®s, Gil Robles asistirâ”œأ­ como observador al primer Congreso de Nâ”œâ•‘remberg del NSDAP, (titulado "Congreso de la Victoria" tras el "fracaso" de la Repâ”œâ•‘blica de Weimar), para aprender de la didâ”œأ­ctica propaganda nazi. En la imagen, colectivo posado tras la ceremonia religiosa en la puerta del Pilar de familiares, testigos y amigos polâ”œآ،ticos del agrarismo espaâ”œâ–’ol. A la izquierda, los diputados Guallar, y Gil Robles. En el centro, la novia y el novio junto al diputado Casanueva. A la derecha extrema, el diputado Royo Villanova. Fuente visual: Foto Marâ”œآ،n Chivite, "Nuevo Mundo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65627200, -0.87803100, '0101000020E610000040F9BB77D418ECBFE8A38CB800D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21339037974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21339037974.webp', 'https://www.flickr.com/photos/zaragozaantigua/21339037974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21793, 'Pl. del Pilar c.1934', 'Imagen de la esquina oriental de la antigua plaza del Pilar, inmediata a la "Puerta Baja" del templo del Pilar; a la torre Nueva, o de Nuestra Seâ”œâ–’ora del Pilar de dicho templo; al callejâ”œâ”‚n del "Retiro Bajo del Pilar", que conectaba con el paseo del Ebro; y al arranque de la calle del Pilar, al fondo, hacia la derecha. Se trata de uno de esos espacios desaparecidos tras la "remodelaciâ”œâ”‚n" de la plaza, unos aâ”œâ–’os despuâ”œآ®s. La manzana de edificios de primer plano, entre la plaza del Pilar y la trasera calle de Latassa (antigua de Talamantes), serâ”œأ­ integralmente demolida, y las viviendas de ambos lados de la calle del Pilar, hasta la Lonja, igual. Se considerâ”œâ”‚ que todas las antiguas casonas de esta parte de la ciudad no tenâ”œآ،an remedio, y que la mejor forma de "sanear", era derribar. Sic transit gloria Urbis. Fuente visual: Joaquâ”œآ،n Gil Marraco (Catâ”œأ­logo Exposiciâ”œâ”‚n grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaciâ”œâ”‚n de Josâ”œآ® Luis Cintora.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65605800, -0.87805700, '0101000020E61000008FC360FE0A19ECBFBC2363B5F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24520610512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24520610512.webp', 'https://www.flickr.com/photos/zaragozaantigua/24520610512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21813, 'Plaza del Pilar 1932', '"Plaza del Pilar y vista parcial", 1932. Imagen de la postal nâ”¬â•‘ 7 de la 2â”¬آ¬ serie de la colecciâ”œâ”‚n "Rellev" dedicada a Zaragoza, puesta en marcha por J. Codina Torrâ”œأ­s a principios de la dâ”œآ®cada de los aâ”œâ–’os 30 del pasado siglo. Ofrece dos interesantes partes: abajo, fragmento de la plaza del Pilar y de las construcciones que la separaban de la plaza de la Seo; arriba, panorama del casco urbano hacia el este, con la torre de la Magdalena en el centro. Fuente: Ajuntament de Girona, Servei de Gestiâ”œâ”‚ Documental, Arxius i Publicacions.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30547671595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30547671595.webp', 'https://www.flickr.com/photos/zaragozaantigua/30547671595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21819, 'Plaza del Pilar 1938', 'Funeral por Josâ”œآ® Antonio Primo de Rivera, con su nombre en la basâ”œآ،lica del Pilar, celebrado en noviembre de 1938, dos aâ”œâ–’os despuâ”œآ®s de su ocultada muerte. Fuente: www.keecua.com/', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65630100, -0.87846800, '0101000020E610000012A452EC681CECBF82AAD1AB01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31509096895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31509096895.webp', 'https://www.flickr.com/photos/zaragozaantigua/31509096895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21891, 'Plaza del Pilar 1939', 'Imagen capturada en la plaza del Pilar y centrada en la cola formada por seâ”œâ–’oras y seâ”œâ–’oritas, algunas ataviadas a la antigua, muchas de riguroso luto, esperando para ingresar al homâ”œâ”‚nimo templo durante la festividad del Corpus. Al fondo, fachadas de los inmuebles del lado este de la plaza, que daban continuidad a la calle de Damiâ”œأ­n Forment, y que poco despuâ”œآ®s serâ”œآ،an derribados. Entre la arboleda, vista parcial de dos de los quioscos que flanqueaban el ingreso a la Puerta Baja del templo.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65608800, -0.87829400, '0101000020E61000009DBCC804FC1AECBF26A60BB1FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49912995286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49912995286.webp', 'https://www.flickr.com/photos/zaragozaantigua/49912995286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21895, 'Plaza del Pilar 1939', 'Imagen capturada en la plaza del Pilar y centrada en la cola formada por la grey que aguarda para ingresar al homâ”œâ”‚nimo templo durante la festividad del Corpus por la Puerta Baja, que de forma excepcional se muestra sin la decimonâ”œâ”‚nica contrapuerta o cancel en madera de nogal que habitualmente oculta los originales y barrocos aderezos que aquâ”œآ، se muestran al aire.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65629600, -0.87820800, '0101000020E6100000F9BCE2A9471AECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50064751296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50064751296.webp', 'https://www.flickr.com/photos/zaragozaantigua/50064751296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21938, 'Guardia Mora 1946', 'Comitiva del dictador Franco a su paso por la calle de Alfonso I, llegando a la plaza del Pilar. Al fondo a la izquierda, la calle de Santiago. A la derecha, la de Prudencio. La Guardia Mora estaba compuesta por soldados marroquâ”œآ،s musulmanes del Ejâ”œآ®rcito de â”œأ¼frica y que ejerciâ”œâ”‚ de escolta de gala del dictador hasta 1que el Râ”œآ®gimen reconociâ”œâ”‚ la independencia del Reino de Marruecos en 1956.', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65596100, -0.87920400, '0101000020E61000007365506D7022ECBFC939B187F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15315831659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15315831659.webp', 'https://www.flickr.com/photos/zaragozaantigua/15315831659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21940, 'Ayuntamiento 1946', 'Enero de 1946. Las autoridades, con notable presencia de las religiosas en la imagen, asisten a la ceremonia de colocaciâ”œâ”‚n de la primera piedra del nuevo edificio del Ayuntamiento de Zaragoza en la plaza del Pilar 18. No serâ”œأ­ inaugurado hasta 1965, tras dos dâ”œآ®cadas de obras. Fuente: www.facebook.com/photo.php?fbid=842175925805034&set=o...', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65617600, -0.87724100, '0101000020E610000013BBB6B75B12ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15596914398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15596914398.webp', 'https://www.flickr.com/photos/zaragozaantigua/15596914398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21999, 'Plaza del Pilar 1944', 'Imagen capturada en el entorno de la antigua y arbolada plaza del Pilar, en las inmediaciones de la puerta "Baja" y los quioscos que flanqueaban su acceso. La fotografâ”œآ،a se ha realizado desde el solar de la desaparecida manzana entre la plaza, y la calle de Latassa, derribada durante el proceso de ampliar la plaza, por el este, hasta la calle de Don Jaime I. La fachada sur del Pilar presenta el prâ”œآ،stino y sobrio aspecto original. Fuente visual: foto Casas Torras, en www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33631073801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33631073801.webp', 'https://www.flickr.com/photos/zaragozaantigua/33631073801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22003, 'Aâ”œآ®rodromo Sanjurjo 1941', 'Imagen promocional del Aero Club Zaragoza en su nueva ubicaciâ”œâ”‚n del aerâ”œâ”‚dromo Sanjurjo, con dos de los cuatro aparatos con que contaba en esas fechas, dos RWD-13 adquiridos como material de guerra por la aviaciâ”œâ”‚n nacionalista a la entonces independiente Polonia, y transferidos en 1940 al Aero Club Zaragoza en su resurgimiento tras la guerra. Con la presidencia de Luis Baselga de Yarza, este club funcionaba como Escuela Oficial de pilotos civiles. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œأ­fica de cultura aragonesa".', 1941, 1941, 1941, 'Anos 40', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34640175246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34640175246.webp', 'https://www.flickr.com/photos/zaragozaantigua/34640175246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22024, 'Calle del Pilar 1941', 'Imagen capturada en la recoleta calle del Pilar con una vista sâ”œâ”‚lo posible tras el derribo de las manzanas de viviendas comprendidas a espaldas del fotâ”œâ”‚grafo entre la plaza del Pilar y las calles de Latassa y Bayeu, que permite esta panorâ”œأ­mica desde el extremo mâ”œأ­s sureâ”œâ–’o del templo del Pilar, donde en la câ”œâ•‘pula de la capilla de la Virgen destaca el fonograma traâ”œآ،do desde la Alemania nazi con la tradicionalista jaculatoria "Bendita y alabada sea" y etc, e instalado con motivo del 19 centenario de la "llegada de la Virgen". A continuaciâ”œâ”‚n, el Retiro Bajo, y el primer gran tramo de los inmuebles impares de la calle del Pilar, comprendido entre los nâ”œâ•‘meros 3 y 15. En este â”œâ•‘ltimo se encontraba la tienda de alimentaciâ”œâ”‚n "Casa Delatas", vecina a la gran casa que fuera de los marqueses de Ayerbe, cuya verja de su ingreso principal se destaca en primer tâ”œآ®rmino. Poco despuâ”œآ®s todos estos edificios serâ”œآ،an derribados para construir el edificio de la nueva Casa Consistorial.', 1941, 1941, 1941, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65604000, -0.87761800, '0101000020E610000090300C587215ECBF156F641EF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50147039346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50147039346.webp', 'https://www.flickr.com/photos/zaragozaantigua/50147039346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22031, 'Calle de Alfonso I 1944', 'Imagen capturada en la calle de Alfonso I durante la cuarta salida de la comparsa de Gigantes y Cabezudos programada en las Fiestas del Pilar. Viniendo desde la Hospederâ”œآ،a del Pilar, la festiva procesionaria se encamina hacia la calle de la Manifestaciâ”œâ”‚n. Sobre el "Torero" pende una recordatorio de la IV Feria Nacional de Muestras. Al fondo, la tradicional fachada del templo del Pilar, antes del inicio de las obras de reforma que la mantuvieron andamiada unos cuantos aâ”œâ–’os.', 1944, 1944, 1944, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65613600, -0.87928100, '0101000020E61000004AD05FE81123ECBF37DDB243FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51708340745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51708340745.webp', 'https://www.flickr.com/photos/zaragozaantigua/51708340745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22060, 'Paisano Franco 1953', 'Ayuntamiento de Zaragoza/Marâ”œآ،n Chivite. 21 de junio 1953. Visita de Francisco Franco a Zaragoza. Imagen a la salida de rendir homenaje a la patrona de la Hispanidad en el Templo del Pilar. A su lado, el Alcalde de la ciudad entre 1949 y 1954, Josâ”œآ® Marâ”œآ،a Garcâ”œآ،a-Belenguer y Garcia, del partido "Movimiento Nacional".', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65624800, -0.87813900, '0101000020E6100000D8F2CAF5B619ECBF5F0839EFFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938046145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938046145.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938046145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22062, 'Gran Plaza del Pilar 1954', 'AHPZ. Archivo Coyne. Manuel Coyne. "Plaza del Pilar". Perdura la huella de las manzanas de edificios derribadas para mayor gloria del espacio abierto desde las murallas hasta la Seo. El nuevo Ayuntamiento sigue en obras.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65595200, -0.87817600, '0101000020E6100000213A048E041AECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15027632141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15027632141.webp', 'https://www.flickr.com/photos/zaragozaantigua/15027632141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22086, 'Infantes Reales en plaza del Pilar 1950', 'Juan de Borbâ”œâ”‚n, cabeza de la Casa Real espaâ”œâ–’ola, y la princesa Marâ”œآ،a de las Mercedes de Borbâ”œâ”‚n-Dos Sicilias tuvieron dos hijas y dos hijos. Juan Carlos y Alfonso nacieron en Roma (Repâ”œâ•‘blica de Italia), ciudad en la que se hallaban exiliados. Tras unos aâ”œâ–’os en Lausana (Repâ”œâ•‘blica de Suiza), en 1946 la familia se estableciâ”œâ”‚ en Estoril (Repâ”œâ•‘blica de Portugal). En 1950, Alfonso y Juan Carlos fueron enviados a estudiar al Reino de Espaâ”œâ–’a, al colegio instalado en el Palacio de Miramar (San Sebastiâ”œأ­n), antigua residencia de verano de la Familia Real. Desde allâ”œآ،, realizaron algunos viajes a ciudades como Valencia, Madrid, Sevilla... y Zaragoza. En la imagen, llegada de los infantes Juan Carlos (13 aâ”œâ–’os de edad) y Alfonso de Borbâ”œâ”‚n (10 aâ”œâ–’os de edad) a la plaza del Pilar, para visitar la basâ”œآ،lica concatedral, en octubre de 1951. Juan Carlos ha descendido ya del coche, y estâ”œأ­ a punto de hacerlo su hermano. Detrâ”œأ­s de los infantes, imagen de la obra del nuevo edificio que serâ”œأ­ la sede del Gobernador Civil. Al fondo, a la izquierda, apenas visible a contraluz, la torre de la Seo.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65607000, -0.87830700, '0101000020E6100000C4211B48171BECBF80F10C1AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16741759737.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16741759737.webp', 'https://www.flickr.com/photos/zaragozaantigua/16741759737/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22102, 'Pl. del Pilar 1954', 'Desde la torre de la Seo, posiblemente en el tercer cuerpo, vista en altura de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca para convertirse en escenario de multitudinarias ceremonias de reafirmaciâ”œâ”‚n del râ”œآ®gimen franquista. En primer tâ”œآ®rmino y a la izquierda, obras en progresiâ”œâ”‚n del Gobierno civil y a la derecha las del ayuntamiento, en este caso con especial desarrollo en la fachada recayente a la plaza. Las dos nuevas torres del Pilar, patrocinadas econâ”œâ”‚micamente por Francisco Urzaiz y Leonor Sala, todavâ”œآ،a parecen ascender en sintonâ”œآ،a, y la fachada sur del templo ya presenta su nuevo aspecto escultâ”œâ”‚rico resultante tras la reforma proyectada por Teodoro Râ”œآ،os Balaguer. Fuente: rafaelcastillejo.com', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20523007218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20523007218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20523007218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22148, 'Plaza del Pilar 1951', 'Uno de los â”œâ•‘ltimos veranos de los jardines, â”œأ­rboles y bancos de la antigua plaza del Pilar, y tambiâ”œآ®n de los quioscos que flanqueaban el ingreso a la puerta Baja del templo metropolitano. Al fondo, despejada vista de la torre de la Seo tras el derribo de las manzanas de viviendas de la antigua calle de Latassa y de los tramos finales de las calles de Forment y de Bayeu. A la izquierda, la arboleda impide ver las obras del nuevo ayuntamiento. A la derecha despuntan iluminados los caâ”œâ–’izos y andamios del nuevo Gobierno civil en construcciâ”œâ”‚n, y abajo, entre sombras, los muretes tras los que se estaba derribando la manzana de casas entre la plaza y la calle de Goicoechea. Fuente visual: www.ebay.es/', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26638300090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26638300090.webp', 'https://www.flickr.com/photos/zaragozaantigua/26638300090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22153, 'El Pilar 1951', 'Aspecto de la fachada del Pilar, cubierta por andamios durante sus obras de restauraciâ”œâ”‚n. Fuente: Revista La Cadiera.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28979829518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28979829518.webp', 'https://www.flickr.com/photos/zaragozaantigua/28979829518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22172, 'Pl. del Pilar 1958', 'Imagen capturada durante los ceremoniales oficiales programados con motivo del traslado de los restos mortales de Josâ”œآ® Rebolledo de Palafox y Melci al selecto carneario de la basâ”œآ،lica del Pilar. Mientras la procesionaria se encamina al templo por la puerta "alta", el fotâ”œâ”‚grafo nos regala una insâ”œâ”‚lita visual, al fondo, del antiguo emboque a la calle de los Convertidos, con el antiguo edificio del nâ”¬â•‘ 30 de la plaza, a la izquierda, y una mâ”œأ­s extraordinaria vista de algunos edificios de la calle de las Danzas, a la derecha (posiblemente, el nâ”¬â•‘ 20, y el 22), pues la antigua manzana entre la plaza del Pilar, y la calle de las Danzas ya habâ”œآ،a sido derribada para ajustar perfectamente el regular perfil de la nueva y gran plaza del Pilar. y para poder construir en esa ubicaciâ”œâ”‚n los nuevos edificios de los juzgados de la ciudad. La manzana entre la calle de las Danzas, y la calle de Prudencio, perdurarâ”œآ،a hasta su postrer derribo, mâ”œأ­s adelante, al objeto de ampliar los edificios de los juzgados. Asâ”œآ، desapareciâ”œâ”‚ una de las calles mâ”œأ­s antiguas de la ciudad. Fuente visual: foto ALPI, AMZ.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65627400, -0.87954800, '0101000020E61000000264E8D84125ECBF899B53C900D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31456685226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31456685226.webp', 'https://www.flickr.com/photos/zaragozaantigua/31456685226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22178, 'Pl. del Pilar 1954', 'Eucaristâ”œآ،a vespertina celebrada en la plaza del Pilar, con motivo del Congreso Mariano Nacional, celebrado en octubre de 1954. Fuente: foto Marâ”œآ،n Chivite, en HA.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65647400, -0.87906000, '0101000020E6100000A818E76F4221ECBF50560C5707D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616241272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616241272.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616241272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22190, 'Plaza del Pilar 1954', 'Tractor durante las obras de la plaza del Pilar y su entorno en 1954. A la izquierda, andamios en el Ayuntamiento en construcciâ”œâ”‚n. Al fondo, la torre de la Seo. Fuente: Heraldo.es', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65613800, -0.87824500, '0101000020E610000043041C42951AECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32232564354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32232564354.webp', 'https://www.flickr.com/photos/zaragozaantigua/32232564354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22355, 'Plaza del Pilar c.1962', 'Plaza del Pilar. Fuente: rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20708306485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20708306485.webp', 'https://www.flickr.com/photos/zaragozaantigua/20708306485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22369, 'Majorettes 1969', 'Primer desfile del grupo de majorettes de Zaragoza, durante el pregâ”œâ”‚n de las fiestas del Pilar, el 11 de octubre de 1969. A la derecha, puerta del Ayuntamiento.', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65599000, -0.87759800, '0101000020E6100000C91EA1664815ECBF6440F67AF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21547340246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21547340246.webp', 'https://www.flickr.com/photos/zaragozaantigua/21547340246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22455, 'Zaragoza 1965', 'Representaciâ”œâ”‚n escultâ”œâ”‚rica esquemâ”œأ­tica de la ciudad de Zaragoza, sostenida en sus manos por el "â”œأ¼ngel de la Ciudad", o â”œأ¼ngel Custodio, obra de Pablo Serrano que forma parte de un conjunto de dos (la otra es San Valero). Flanquean la entrada del Ayuntamiento en la plaza del Pilar, y fueron encargadas por â”œآ®ste en 1964 y colocadas en 1965. Fuente: Wikipedia.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65598000, -0.87755600, '0101000020E61000000E130D52F014ECBF406A1327F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31618605092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31618605092.webp', 'https://www.flickr.com/photos/zaragozaantigua/31618605092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22574, 'Calle de Alfonso I 1973', 'Câ”œآ®sar Sâ”œأ­nchez Vâ”œأ­zquez. 1973. Calle de Alfonso I, en imagen capturada desde su embocadura en la plaza del Pilar. Destacan las farolas tridentinas instaladas en 1972. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65604800, -0.87909800, '0101000020E61000000954FF209221ECBF984D8061F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15413572678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15413572678.webp', 'https://www.flickr.com/photos/zaragozaantigua/15413572678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22689, 'Plaza del Pilar c.1972', 'Imagen tomada desde una plaza del Pilar poblada de vehâ”œآ،culos a motor ante el Ayuntamiento y ajardinada, con la tâ”œآ،pica imagen de las palomas arremolinadas en torno a quienes les arrojaban comida. Al fondo, la Lonja y la catedral de San Salvador, mâ”œأ­s conocida como la Seo, con su esbelta torre barroca. Este entorno fue muy remodelado en la gran intervenciâ”œâ”‚n de 1991.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65606100, -0.87811400, '0101000020E61000009F1C05888219ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26812388113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26812388113.webp', 'https://www.flickr.com/photos/zaragozaantigua/26812388113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22690, 'Pl. del Pilar 1970', 'Imagen capturada al atardecer y centrada en el antiguo ingreso del Retiro Bajo de la basâ”œآ،lica de Nuestra Seâ”œâ–’ora del Pilar, tal como reza la lâ”œأ­pida adosada a la derecha, aâ”œâ–’os mâ”œأ­s tarde sustituida por una nueva ya con la superlativa categorâ”œآ،a de "basâ”œآ،lica catedral". Esta puerta de toda la vida fue realizada en 1849 en madera por el escultor bilbilitano Josâ”œآ® Alegre, que tallâ”œâ”‚ los relieves , y el carpintero Manuel Sarte. Dos pequeâ”œâ–’os maceteros flanquean el ingreso, cuyas puertas de madera presentan una tonalidad bien acorde, y el intradâ”œâ”‚s del arco de medio punto ignora el farol que aâ”œâ–’os despuâ”œآ®s le serâ”œآ،a colocado. Una persona se viene y otra se va, y nosotros nos iremos, y no volveremos mâ”œأ­s. Fuente visual: www.flickr.com/photos/152234007@N06/35072130063/in/album-...', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65631700, -0.87825100, '0101000020E6100000CBBC55D7A11AECBF8867093202D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26873394447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26873394447.webp', 'https://www.flickr.com/photos/zaragozaantigua/26873394447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22860, 'Desde San Nicolâ”œأ­s al Pilar 1987', 'Luis Mâ”œآ،nguez. 1987. Desde la barroca torrecilla de San Nicolâ”œأ­s de Bari (convertida en 1902 en iglesia monacal de las Comendadoras Canonesas del Santo Sepulcro), una visual hasta la basâ”œآ،lica del Pilar. Su modesto tamaâ”œâ–’o hace que la vista sea una sucesiâ”œâ”‚n de tejados: los propios del Pilar, con las polâ”œآ،cromas tejas de las câ”œâ•‘pulas menores, y las torres en perspectiva caballera; el de la Lonja, con sus cuatro torrecitas angulares; el torreoncillo del complejo arzobispal; las viviendas de la calle Sepulcro con San Vicente de Paâ”œâ•‘l, y las inmediatas viviendas de la calle Boterâ”œâ”‚n, que aâ”œâ–’os despuâ”œآ®s serâ”œأ­n piqueteadas y convertidas en nuevos bloques habitacionales, en 4 alturas y formas integradas en el entorno.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65652100, -0.87788700, '0101000020E610000075AC527AA617ECBF901150E108D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15650433738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15650433738.webp', 'https://www.flickr.com/photos/zaragozaantigua/15650433738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23771, 'Puente Z-40 2007', 'Foto: Esther Casas. Vista de la construcciâ”œâ”‚n del puente de la Z-40 o Cuarto Cinturâ”œâ”‚n, en febrero de 2007. Estâ”œأ­ tomada desde la margen izquierda del râ”œآ،o Ebro, en las cercanâ”œآ،as de Movera. Al fondo, el polâ”œآ،gono industrial Montemolâ”œآ،n, junto a la carretera de Castellâ”œâ”‚n. Este puente serâ”œأ­ inaugurado en junio de 2008. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.63218100, -0.83801200, '0101000020E610000048FAB48AFED0EABF8813984EEBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31385371024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31385371024.webp', 'https://www.flickr.com/photos/zaragozaantigua/31385371024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22954, 'Vista desde el Pilar c.1986', 'Interesante vista capturada en despejada altura desde la torre de San Francisco de Borja del Pilar (la del ascensor), con un interesante panorama del suroeste urbano hasta el entorno de la Romareda. En primer tâ”œآ®rmino, la prâ”œآ،stina torre de Santiago, erigida en tiempos barrocos. si bien culminada a finales del siglo XIX. Inmediato, a la derecha, uno de los espacios de aparcamiento en superficie entonces habilitados en la plaza del Pilar, en este caso en la zona cercana al "Monumento a los Hâ”œآ®roes y Mâ”œأ­rtires de Zaragoza caâ”œآ،dos en la Cruzada de Liberaciâ”œâ”‚n 1936-1939". A la izquierda, la calle de Alfonso I. En las traseras de los Juzgados, despejada vista de la alabeada calle de Prudencio por los solares de antiguas viviendas que poco despuâ”œآ®s serâ”œآ،an utilizados para ampliaciâ”œâ”‚n de las dependencias judiciales. Hacia el fondo, diversos jalones edilicios de la moderna ciudad, alcanzando hasta los tremebundos bloques Marvel junto al cauce del râ”œآ،o Huerva y la calle del Arzobispo Morcillo. Fuente visual: foto giuseppedibari, en www.flickr.com', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43650658822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43650658822.webp', 'https://www.flickr.com/photos/zaragozaantigua/43650658822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23037, 'Ratâ”œâ”‚n Mickey 1994', 'Imagen capturada ante la puerta principal del Ayuntamiento, cuando el alcalde Antonio Gonzâ”œأ­lez Triviâ”œâ–’o entrega pâ”œâ•‘blicamente la Llave de Oro de la ciudad de Zaragoza al ratâ”œâ”‚n Mickey en marzo de ese aâ”œâ–’o. Este acto se enmarcâ”œâ”‚ en la campaâ”œâ–’a de promociâ”œâ”‚n del espectâ”œأ­culo sobre hielo titulado La Bella y la Bestia que la compaâ”œâ–’â”œآ،a Walt Disney programâ”œâ”‚ en Espaâ”œâ–’a, de forma que Zaragoza (Pabellâ”œâ”‚n Municipal Prâ”œآ،ncipe Felipe) fue escogida junto a Barcelona y Madrid como los privilegiados escenarios elegidos para finalizar la gira europea de este espectâ”œأ­culo. En la escena, un sonriente alcalde ofrece al no menos sonriente personaje del ratâ”œâ”‚n Mickey, monarca del entretenimiento familiar, una reproducciâ”œâ”‚n de las honorâ”œآ،ficas llaves que fueron originalmente entregadas al Deseado rey Fernando VII cuando en 1814 visitâ”œâ”‚ Zaragoza.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65593600, -0.87757500, '0101000020E6100000BE30992A1815ECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50368117333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50368117333.webp', 'https://www.flickr.com/photos/zaragozaantigua/50368117333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23043, 'Cumbre de alcaldes 1994', 'Imagen capturada en el Salâ”œâ”‚n de Plenos del Ayuntamiento durante la reuniâ”œâ”‚n de alcaldes europeos de la Red C6, macro regiâ”œâ”‚n considerada "la puerta de Europa" e integrada por los municipios de Zaragoza, Barcelona, Valencia, Palma de Mallorca, Toulouse y Montpellier, con motivo del ceremonial relevo en la presidencia de esta entidad, que durante seis meses ostentâ”œâ”‚ el alcalde de Zaragoza, y que desde entonces recayâ”œâ”‚ en el de Barcelona. En la imagen, acto de presentaciâ”œâ”‚n de El Libro Verde del Medio Ambiente, con presencia de los alcaldes de Toulouse (Dominique Baudis), Valencia (Rita Barberâ”œأ­), Zaragoza (Antonio Gonzâ”œأ­lez Triviâ”œâ–’o), Barcelona (Pasqual Maragall), Palma de Mallorca (Joan Fageda) y Montpellier (alcalde adjunto, Bernard Fabre).', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65628000, -0.87729600, '0101000020E6100000F52B9D0FCF12ECBF6B82A8FB00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50382031062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50382031062.webp', 'https://www.flickr.com/photos/zaragozaantigua/50382031062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23113, 'Vista aâ”œآ®rea 2004', 'Vista aâ”œآ®rea de Zaragoza en 2004, centrada en la plaza del Pilar. Fuente: www.facebook.com/photo.php?fbid=1777983065797482&set=...', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65657400, -0.87932600, '0101000020E61000004AB890477023ECBFB3B3E89D0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30738105011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30738105011.webp', 'https://www.flickr.com/photos/zaragozaantigua/30738105011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23168, 'Plaza del Pilar 2000', 'Ilustraciâ”œâ”‚n que acompaâ”œâ–’a un texto firmado en 1979 por Alfonso Solâ”œأ­ns Serrano, concejal de Trâ”œأ­fico y Policâ”œآ،a Municipal del Ayuntamiento de Zaragoza. Vemos el subsuelo de la plaza del Pilar, surcado por varias unidades de metro, en un ejercicio de prospectiva que sitâ”œâ•‘a este escenario en el aâ”œâ–’o 2000. El horadamiento, mâ”œأ­s modesto, se llevâ”œâ”‚ a cabo en 1991 para la construcciâ”œâ”‚n de un aparcamiento subterrâ”œأ­neo. Fuente: "Trâ”œأ­fico y transporte en la Zaragoza 2000". Ayuntamiento de Zaragoza, 1979.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65642600, -0.87893100, '0101000020E610000033198EE73320ECBF3F1F65C405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32950518995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32950518995.webp', 'https://www.flickr.com/photos/zaragozaantigua/32950518995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23279, 'Câ”œآ®sar Augusto al pregâ”œâ”‚n 1961', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 1961. Podrâ”œآ،a pasar por uno de los varios traslados de la estatua de Câ”œآ®sar Augusto por la ciudad, pero no. Se trata de una de las carrozas participantes en el pregâ”œâ”‚n de las fiestas mayores de la ciudad, rodando por la calle Alfonso I, a punto de llegar a la Plaza del Pilar. Intenta ser una carroza romana, pero si el auriga es el hombre de hojalata, pues no.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65597700, -0.87920600, '0101000020E6100000A14D0E9F7422ECBFCFF6E80DF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817567187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817567187.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817567187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23288, 'Calle de Alfonso I 1958', 'Octubre de 1958. Calle de Alfonso I de Zaragoza. Al fondo, la confluencia con la plaza del Pilar. En el centro, imagen de la Virgen con las flores de la primera ofrenda realizada. Fuente: Colecciâ”œâ”‚n Josâ”œآ® Vicente Moreno.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65595200, -0.87917500, '0101000020E6100000E0BE0E9C3322ECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15810476761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15810476761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15810476761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23300, 'Calle de Alfonso I 1967', 'La reina de las fiestas del Pilar de 1967 lleva en sus manos la Cruz de Lorena del sanatorio antituberculoso Royo Villanova, para depositarla ante la imagen de la Virgen del Pilar en la ofrenda de flores (antituberculosa). A la derecha, la Librerâ”œآ،a Aragâ”œâ”‚n, que hacâ”œآ،a esquina en la calle de Alfonso I con la plaza del Pilar. Fuente: Agencia EFE', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65612700, -0.87916400, '0101000020E6100000E5417A8A1C22ECBFE48233F8FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23988655753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23988655753.webp', 'https://www.flickr.com/photos/zaragozaantigua/23988655753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23312, 'Calle de Alfonso I c.1976', 'Imagen tomada en el â”œâ•‘ltimo tramo de la calle de Alfonso I y orientada hacia su principio desde el Coso Alto, al fondo. A la izquierda e inmediato, el esquinero comercio de los Almacenes de Mercerâ”œآ،a de Telesforo Garcâ”œآ،a de la Cruz, y el ingreso al Pasaje de la Industria y el Comercio, popularmente denominado El Ciclâ”œâ”‚n. A la derecha, la estimable fachada del establecimiento comercial de Urueâ”œâ–’a (originalmente realizado en 1928 para Madurga y Compaâ”œâ–’â”œآ،a). Hacia el fondo y a la derecha, los cruces que dan acceso al principio de la calle de Prudencio, en primer lugar, y a la de la Manifestaciâ”œâ”‚n, despuâ”œآ®s. El escaso trâ”œأ­nsito peatonal, y nulo rodado, sugieren que tal vez esta fotografâ”œآ،a se realizâ”œâ”‚ en un dâ”œآ،a no laborable. La seâ”œâ–’al de Circulaciâ”œâ”‚n prohibida, por si acaso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65607700, -0.87917400, '0101000020E6100000C9CA2F833122ECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45737794564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45737794564.webp', 'https://www.flickr.com/photos/zaragozaantigua/45737794564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23313, 'Plaza del Pilar 1962', 'Imagen capturada en la plaza del Pilar con la perspectiva de la calle de Alfonso I desde su arranque, al fondo, en el tramo alto del Coso, y centrada en un chaval haciendo prâ”œأ­cticas de Guardia Urbano durante un cursillo de circulaciâ”œâ”‚n impartido por la OJE (Organizaciâ”œâ”‚n de Juventudes Espaâ”œâ–’olas). Tras el soleado muchacho y el Renault Dauphine Gordini que se encamina hacia la calle de Don Jaime I, chaflâ”œأ­n del inmueble del nâ”¬â•‘ 8 de la plaza del Pilar, ocupado en los bajos por la librerâ”œآ،a y tienda de material escolar Aragâ”œâ”‚n. La OJE habâ”œآ،a sido creada en 1960 como refundaciâ”œâ”‚n de dos organizaciones juveniles, la antigua y obligatoria denominada "Frente de Juventudes", y la voluntaria "Falanges Juveniles de Franco", en una nueva organizaciâ”œâ”‚n de carâ”œأ­cter voluntario integrada en el Movimiento Nacional franquista.', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65618400, -0.87919500, '0101000020E6100000A6D0798D5D22ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47968165051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47968165051.webp', 'https://www.flickr.com/photos/zaragozaantigua/47968165051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23790, 'Palacio de Ayerbe aâ”œâ–’os 30', 'Aâ”œâ–’os 30 del siglo XX. Vista del palacio de los Marqueses de Ayerbe desde el Paseo del Ebro. Fue expropiado y derribado en 1942 para construir el nuevo Ayuntamiento. Las lâ”œأ­mparas de la mansiâ”œâ”‚n fueron donadas a la Basâ”œآ،lica de El Pilar. A la izquierda, la Posada de los Reyes. Este palacio fue escenario, a finales del siglo XIX, de renombradas fiestas de sociedad, especialmente durante la visita de la Reina Marâ”œآ،a Cristina en 1888. Fuente visual: Archivo Municipal, Archivo Mora.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65625600, -0.87718900, '0101000020E610000074266DAAEE11ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710919438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710919438.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710919438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23791, 'Pl. del Pilar 1954', 'Jardines, autobâ”œâ•‘s, caballo con carro.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65625900, -0.87884500, '0101000020E61000008F19A88C7F1FECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725322669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725322669.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725322669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23792, 'Palacio de Ayerbe aâ”œâ–’os 30', 'Aâ”œâ–’os 30 del siglo XX. En la calle del Pilar, puerta principal de acceso al palacio de los marqueses de Ayerbe, ocupado en sus â”œâ•‘ltimos aâ”œâ–’os por la congregaciâ”œâ”‚n de las religiosas Angâ”œآ®licas de santa Genoveva. Estas monjas, hoy desplazadas a su Casa Generalicia de la plaza del Pilar 22, se dedican a gestionar hospederâ”œآ،as. Fuente visual: Archivo Municipal, Archivo Mora.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65599500, -0.87756200, '0101000020E610000096CB46E7FC14ECBF75ABE7A4F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14730512220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14730512220.webp', 'https://www.flickr.com/photos/zaragozaantigua/14730512220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23804, 'Copa del balâ”œâ”‚n en el cesto 1984', 'Copa del Rey 1984. De 1933 es el primer Campeonato de Espaâ”œâ–’a de Copa de baloncesto, que desde 1940 se disputâ”œâ”‚ como Copa de Su Excelencia el Generalâ”œآ،simo, y desde 1976 como Copa de Su Majestad el Rey. La ediciâ”œâ”‚n de 1983-1984 se disputâ”œâ”‚ en Zaragoza, y la final fue disputada entre el CAI Zaragoza y el F.C. Barcelona. El resultado final (81-78) dio la victoria al equipo local por primera vez en su historia y fue un acontecimiento calificado, por ello, de histâ”œâ”‚rico. En la imagen, momento estelar de la celebraciâ”œâ”‚n del tâ”œآ،tulo: los jugadores se encaminan hacia la Puerta Alta del Pilar, acompaâ”œâ–’ados de gran nâ”œâ•‘mero de seguidores, para escenificar la ofrenda simbâ”œâ”‚lica de la Copa a la Virgen. Al fondo, la arbolada plaza de La Seo, y a la derecha, la sede del Gobierno Civil, donde todavâ”œآ،a perduran sâ”œآ،mbolos del franquismo, aunque el PSOE gobernaba con mayorâ”œآ،a absoluta en todas las instituciones imaginables.', 1984, 1984, 1984, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65632400, -0.87877500, '0101000020E6100000575BB1BFEC1EECBF3ACAC16C02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15280746708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15280746708.webp', 'https://www.flickr.com/photos/zaragozaantigua/15280746708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23815, 'Pilar 1968', 'Imagen de la "Puerta Baja" del Pilar, o puerta principal por estar mâ”œأ­s cerca de la Virgen. A su derecha queda la "Torre Nueva" del Pilar, asâ”œآ، denominada cuando fue la torre de factura mâ”œأ­s joven, a comienzos del s.XX, tâ”œآ،tulo que le quitaron las dos de la ribera del Ebro, sesenteras ellas. En la imagen, el Pilar con abundante corriente de gente, y de aires, que de forma inusualmente rara la puerta del fondo estâ”œأ­ abierta, y deja ver la arboleda de Macanaz, en la margen izquierda. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65627200, -0.87803100, '0101000020E610000040F9BB77D418ECBFE8A38CB800D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15870381042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15870381042.webp', 'https://www.flickr.com/photos/zaragozaantigua/15870381042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23821, 'Palacio de Ayerbe c.1940', 'Entre las muchas historias e historietas que rodean al nunca bien ponderado palacio de los marqueses de Ayerbe de la calle del Pilar, destaca la que ataâ”œâ–’e a la cercana y antigua casa de Torrellas, en la que brillaba con luz propia su patio en tres alturas soportadas sobre seis columnas, todo un monumento gâ”œâ”‚tico-plateresco sin igual en la ciudad. Derribado en 1865 por la apertura de la calle Alfonso I, su entonces propietario, el Marquâ”œآ®s de Ayerbe, habrâ”œآ،a reciclado algunos de sus componentes para decorar su palacio de calle del Pilar. Asâ”œآ،, por ejemplo, unas finas columnas de traza gâ”œâ”‚tica fueron adosadas como decoraciâ”œâ”‚n de la fachada, y con algunos arcos y capiteles del patio central se compuso un templete, cenador, o "quiosco". En la imagen, el quiosco reciclado de piezas del derribado palacio de Torrellas, instalado en los jardines del palacio de los Ayerbe. A su izquierda, el edificio denominado "Casas de los Infantes", junto al Callejâ”œâ”‚n del Retiro Bajo y el Pilar. Al fondo, la verja con vistas al paseo de la ribera y el Ebro. Cuando este otro palacio de Ayerbe tambiâ”œآ®n caiga, para construir en su solar el actual edificio consistorial, el templete se irâ”œأ­ con el resto de materiales de derribo, sin noticia de que hubiera sido nuevamente reciclado. Fuente visual: AHPZ. Juan Mora Insa.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65621500, -0.87731900, '0101000020E6100000001AA54BFF12ECBF841266DAFED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19148141195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19148141195.webp', 'https://www.flickr.com/photos/zaragozaantigua/19148141195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23831, 'NIâ”œâ–’as de Garabandal 1965', 'El sacerdote zaragozano Luis Luna, en la plaza del Pilar, flanqueado por Loli y Jacinta, dos de las niâ”œâ–’as de San Sebastiâ”œأ­n de Garabandal (Cantabria) que protagonizaron en ese pueblo desde 1961 hasta 1965 variadas visiones de la Virgen del Carmen, el Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, los arcâ”œأ­ngeles san Miguel y san Gabriel y el apâ”œâ”‚stol Santiago, cabalgando el dâ”œآ،a de su fiesta. En el momento de la foto, estas apariciones ya habâ”œآ،an concluido. El pueblo sigue siendo lugar de peregrinaciâ”œâ”‚n, aunque los fenâ”œâ”‚menos paranormales no obtuvieron la aprobaciâ”œâ”‚n oficial de la Iglesia. Se contabilizaron mâ”œأ­s de 2.300 â”œآ®xtasis en 18 meses, lo que da un resultado de mâ”œأ­s de cuatro apariciones diarias. La Virgen profetizâ”œâ”‚ el fin de los tiempos, pero parece algo confuso el momento concreto. Las apariciones marianas o mariofanâ”œآ،as son fenâ”œâ”‚menos de la religiâ”œâ”‚n cristiana, cuyo listado comienza con la del Pilar, precisamente. Suelen provocar resultados turâ”œآ،sticos. Fuente visual: www.catholicrevelations.org/PR/the%20apparitions%20of%20g...', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65607000, -0.87830700, '0101000020E6100000C4211B48171BECBF80F10C1AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21950243813.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21950243813.webp', 'https://www.flickr.com/photos/zaragozaantigua/21950243813/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23835, 'Cabezudos 1967', 'Plaza del Pilar engalanada y con desfile de cabezudos de la comparsa de أ”أ‡آ£Gigantes y Cabezudosأ”أ‡أک. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753821277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753821277.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753821277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23837, 'Gigantes 1967', 'Plaza del Pilar engalanada y con desfile de gigantes de la comparsa de أ”أ‡آ£Gigantes y Cabezudosأ”أ‡أک. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23148013535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23148013535.webp', 'https://www.flickr.com/photos/zaragozaantigua/23148013535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23838, 'Ofrenda de flores 1968', 'Plaza del Pilar durante la ofrenda de flores, aâ”œâ•‘n sin la escultura-retablo de Pablo Serrano en el centro de la fachada, con representaciâ”œâ”‚n de la fabulosa venida de la Virgen del Pilar a la ciudad. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158017162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158017162.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158017162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23839, 'Plaza del Pilar 1965', 'Imagen tomada durante el legendario proceso de construcciâ”œâ”‚n de la nueva Casa Consistorial de la ciudad, ya en su tercera dâ”œآ®cada de laboreo. La captura estâ”œأ­ centrada en el momento de colocaciâ”œâ”‚n del escudo de la ciudad, con su rampante leâ”œâ”‚n en piedra, en la fachada a la plaza del Pilar, justo encima de la puerta principal de ingreso, y debajo del espacio donde luego se colocarâ”œأ­ el reloj que mojonea los dominios de Cronos. Abajo, al nivel de los porches, ya se han instalado los pedestales sobre los que mâ”œأ­s tarde se colocarâ”œأ­n las estatuas de San Valero y del â”œأ¼ngel Custodio, obras de Pablo Serrano, flanqueando la entrada a la casa de todo el vecindario. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23338765971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23338765971.webp', 'https://www.flickr.com/photos/zaragozaantigua/23338765971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23840, 'Plaza del Pilar 1954', 'Imagen de los quioscos que flanqueaban el acceso a la basâ”œآ،lica del Pilar desde la antigua plaza, en la zona de la "Puerta Baja" o principal del templo. Poco tiempo despuâ”œآ®s, â”œأ­rboles y quioscos serâ”œآ،an derribados y desmontados para despejar la visual y el espacio de la nueva plaza. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23566993224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23566993224.webp', 'https://www.flickr.com/photos/zaragozaantigua/23566993224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23843, 'Plaza del Pilar c.1940', 'Vista de la plaza del Pilar desde la torre de Santiago del templo. En la parte superior, parte del caserâ”œآ،o eliminado para ensanchar el espacio de la plaza. Fuente: www.facebook.com/photo.php?fbid=1043104609064066&set=...', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65595000, -0.87818800, '0101000020E610000032AB77B81D1AECBFD5E76A2BF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392821002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392821002.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392821002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23848, 'Pl. del Pilar 1955', 'Un barrendero municipal desempeâ”œâ–’a sus funciones en la plaza del Pilar con el fondo de la puerta sureste o Baja del templo. La imagen recoge otra de las singularidades de la nueva y gran plaza: la precoz instalaciâ”œâ”‚n en sus aledaâ”œâ–’os de una colonia de palomas que pronto se convirtieron en seâ”œâ–’a de identidad de este diâ”œأ­fano espacio. Fuente visual: Foto: Joan Miquel i Quintilla, en barcelonafotoantic.com/', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24795569146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24795569146.webp', 'https://www.flickr.com/photos/zaragozaantigua/24795569146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23851, 'Plaza del Pilar 1955', 'Canicular imagen de la plaza del Pilar, humanizada al reciente gusto por los grandes espacios abiertos, bien despejados de edificios y vegetaciâ”œâ”‚n para favorecer asâ”œآ، una râ”œأ­pida insolaciâ”œâ”‚n veraniega, y un pasmo atroz los dâ”œآ،as de insensato viento norte. La instalaciâ”œâ”‚n de macetillas, como forma de intentar paliar las cosas, es algo enternecedor. Por encima de la iglesia metropolitana de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, despunta la estructura de obra de la nueva torre noroeste, luego denominada de San Francisco de Borja, o "del ascensor". Un sacerdote apura el paso a la busca de resguardo. Esta joya visual fue realizada por el fotâ”œâ”‚grafo francâ”œآ®s Jean Paul Margnac en el verano de 1955, durante su paso por la penâ”œآ،nsula Ibâ”œآ®rica, desde Parâ”œآ،s, y con destino hacia tierras mâ”œأ­s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26699094216/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65609800, -0.87841100, '0101000020E6100000024BAE62F11BECBF4A7CEE04FBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27026490630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27026490630.webp', 'https://www.flickr.com/photos/zaragozaantigua/27026490630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23853, '&quot;Falla&quot; 1940', 'El programa de las "Fiestas de Primavera" del aâ”œâ–’o 1940 incluyâ”œâ”‚ una luminosa innovaciâ”œâ”‚n: la importaciâ”œâ”‚n de la valenciana costumbre de prender fuego a iconos fungibles, denominada "Falla", un antiguo y pagano acto de renovaciâ”œâ”‚n y purificaciâ”œâ”‚n reconvertido, al adscribirlo al patrâ”œâ”‚n catâ”œâ”‚lico de los carpinteros. Por ser la primera vez, la representaciâ”œâ”‚n que fue pasto de la pasiâ”œâ”‚n iconoclasta en la Zaragoza del momento no podâ”œآ،a ser otra que la de la imagen: titulada "Apariciâ”œâ”‚n", en ella el planeta Tierra es sostenido por â”œأ­ngeles, mientras del â”œآ®ter desciende una columna que es posada por otros â”œأ­ngeles menores justo en la romana Caesaraugusta. De espaldas a la trascendente escena, ni mâ”œأ­s ni menos que la fantâ”œأ­stica llegada en carne mortal de la virgen del pilar a Zaragoza, los canâ”œâ”‚nicos cuatro apâ”œâ”‚stoles evangelistas, a lo suyo. Esta local "falla", a la espera de su holocausto, aparece estacionada en la antigua plaza del Pilar, todavâ”œآ،a arbolada. Al fondo, se abre la calle de Alfonso I. Fuente visual: Marâ”œآ،n Chivite, revista "Aragâ”œâ”‚n".', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65631400, -0.87901200, '0101000020E6100000655419C6DD20ECBF17F4DE1802D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27120945983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27120945983.webp', 'https://www.flickr.com/photos/zaragozaantigua/27120945983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23858, 'Juan de Lanuza 1591', '"La prisiâ”œâ”‚n de Lanuza", â”œâ”‚leo sobre lienzo, Carlos Larraz y Micheto, 1858. Representaciâ”œâ”‚n del momento en el que Juan de Lanuza El Joven, Justicia de Aragâ”œâ”‚n (derecha), es apresado por orden de Felipe II. Aunque se dice que fue prendido en el palacio de la Diputaciâ”œâ”‚n del Reino, el escenario del cuadro es el palacio de Torrellas, en la plaza del Pilar, en cuyos sâ”œâ”‚tanos cuentan que fue encarcelado a la espera de su decapitaciâ”œâ”‚n. Fuente visual: www.museodelprado.es', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65597200, -0.87900200, '0101000020E610000081CB63CDC820ECBFBD8BF7E3F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27661482829.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27661482829.webp', 'https://www.flickr.com/photos/zaragozaantigua/27661482829/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23865, 'La Pilara 1982', 'La Pilara en la ceremonia civil que el 10 de octubre de 1982 dio carta de naturaleza a la homâ”œâ”‚nima cabezuda que desde entonces forma parte de la comparsa local, en una imagen capturada en el balcâ”œâ”‚n principal del Ayuntamiento y en la que Pilar Lahuerta Cajo posa entre el alcalde Ramâ”œâ”‚n Sainz de Varanda y La Pilara cabezuda. De esta forma se homenajeaba a esta veterana vedette de music-hall en el Salâ”œâ”‚n Oasis de Zaragoza, primer cabaret de la ciudad que comenzâ”œâ”‚ siendo el Royal Concert. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1982, 1982, 1982, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30183732101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30183732101.webp', 'https://www.flickr.com/photos/zaragozaantigua/30183732101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23866, 'Plaza del Pilar 1989', 'Tradicional ofrenda de flores realizada desde 1958 en el marco de las fiestas mayores en octubre, y que desde 1969 culminaba en la escultura de Pablo Serrano titulada Venida de la Virgen del Pilar, adosada a la basâ”œآ،lica. En la imagen figuran, de izquierda a derecha, el delegado del Gobierno en Aragâ”œâ”‚n y gobernador Civil, Carlos Pâ”œآ®rez Anadâ”œâ”‚n; el alcalde, Antonio Gonzâ”œأ­lez Triviâ”œâ–’o; y el presidente de la Diputaciâ”œâ”‚n Provincial, Josâ”œآ® Marco Berges. Estos dos â”œâ•‘ltimos portan la vara de mando con que fueron investidos. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65647100, -0.87876700, '0101000020E6100000A1BAB9F8DB1EECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30630443061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30630443061.webp', 'https://www.flickr.com/photos/zaragozaantigua/30630443061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23881, 'Pl. del Pilar 1903', 'Entramado junto a la puerta baja de la basâ”œآ،lica, con escaleras de acceso a una râ”œآ®plâ”œآ،ca de la Virgen del Pilar, durante la celebraciâ”œâ”‚n el 19 de marzo de 1903 de la inauguraciâ”œâ”‚n de las obras de la segunda torre del Pilar, que terminarâ”œأ­ de ser erigida en 1907 en ese punto del templo. Fuente visual: Foto Manuel Olivar', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65621300, -0.87814600, '0101000020E6100000779FE3A3C519ECBFE31A9FC9FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31448215390.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31448215390.webp', 'https://www.flickr.com/photos/zaragozaantigua/31448215390/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23889, 'Barâ”œâ”‚n Von Wichmann 1940', 'El barâ”œâ”‚n Gerhard Von Wichmann, teniente coronel del ejâ”œآ®rcito imperial del kâ”œأ­iser Guillermo, posa con una familiar en la boda de una de sus hijas en 1940, posiblemente en la puerta del Pilar. Este aristâ”œâ”‚crata fue uno de los 347 "alemanes del Camerâ”œâ•‘n" residentes en Zaragoza, desde que en 1916 los ejâ”œآ®rcitos francâ”œآ®s y britâ”œأ­nico conquistaron esa colonia germana. Tras pasar por la Guinea Espaâ”œâ–’ola, llegaron a Espaâ”œâ–’a, que les dio asilo. Von Wichmann se casâ”œâ”‚ con una ejeana en 1921 y viviâ”œâ”‚ en la calle de Ponciano Ponzano, donde eran câ”œآ®lebres sus fiestas. La "pequeâ”œâ–’a Alemania" tuvo una destacada influencia social y econâ”œâ”‚mica en la ciudad: Colegio Alemâ”œأ­n en la calle de Cervantes (con su secciâ”œâ”‚n de las Juventudes Hitlerianas en 1939), Casa de los Alemanes en Moncasi, foto Carlos Skogler en el Coso, Tinte de los Alemanes, salchichas Kurtz, cementerio alemâ”œأ­n, cervezas La Zaragozana (Hans Schneider), guantes Schoeman, mâ”œآ®todo de producciâ”œâ”‚n de la Azucarera, impulso del balompiâ”œآ® con el campo de la calle Bilbao... Fuente: "La herencia germana de Zaragoza", Sergio del Molino, Heraldo de Aragâ”œâ”‚n, 2007.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65630900, -0.87827500, '0101000020E6100000ED9E3C2CD41AECBF0589EDEE01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32169099336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32169099336.webp', 'https://www.flickr.com/photos/zaragozaantigua/32169099336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23896, 'Ayuntamiento 1965', 'Imagen capturada en el interior del despacho del Sr. Alcalde en el nuevo edificio del ayuntamiento de Zaragoza. El maravilloso artesonado de la techumbre (comienzos del siglo XVI) pertenecâ”œآ،a originalmente a la derribada casa de los marqueses de Osera en la antigua calle Mayor, junto a la iglesia de Santa Cruz. El moderno mobiliario fue adquirido a la emblemâ”œأ­tica empresa Simâ”œâ”‚n Loscertales Bona. Al fondo, el lienzo de Francisco Marâ”œآ،n Bagâ”œâ•‌â”œآ®s titulado "Retrato del general Francisco Franco Bahamonde" (1939). Fuente visual : El Ayuntamiento de Zaragoza (1977).', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38307606071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38307606071.webp', 'https://www.flickr.com/photos/zaragozaantigua/38307606071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23898, 'Plaza del Pilar 1985', 'Imagen capturada en la plaza del Pilar durante el paso de un ciudadano con sus campaneros pantalones ante la fachada principal del Ayuntamiento. La escultura de San Valero, realizada por Pablo Serrano e instalada veinte aâ”œâ–’os antes en esa ubicaciâ”œâ”‚n, a la diestra del ingreso municipal, deviene en apariciâ”œâ”‚n siniestra por el capricho de las sombras de un atardecer canicular.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48773887311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48773887311.webp', 'https://www.flickr.com/photos/zaragozaantigua/48773887311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23911, 'Templo del Pilar 1940', 'Inâ”œآ®dita imagen capturada ante la puerta Baja del templo del Pilar, con un posado en el que la "Excelentâ”œآ،sima seâ”œâ–’ora dona Carmen Polo, esposa de su excelencia el Jefe del Estado" y Ramâ”œâ”‚n Serrano Suâ”œâ–’er, "Excelentâ”œآ،simo Sr. Ministro de la Gobernaciâ”œâ”‚n", flanquean a los dos hijos de â”œآ®ste, "Pepito y Fernando Serrano Polo" disfrazados de Infantes del Pilar (habâ”œآ،an sido nombrados Infantes de Honor), su madre, "doâ”œâ–’a Zita Polo de Serrano". y su prima "Carmencita Polo de Franco". Esta foto fue tomada tras la ceremonia en la que Pepito y Fernando recibieron por vez primera "el Pan de los â”œأ¼ngeles" o "cuerpo de Cristo escondido bajo la apariencia de pan" en la Santa Capilla del Santo Templo Metropolitano del Pilar el dâ”œآ،a 30 de mayo (festividad de San Fernando III) del aâ”œâ–’o 1940, coincidente con la solemne conmemoraciâ”œâ”‚n por el Râ”œآ®gimen del XIX Centenario de "la venida de la Virgen del Pilar en carne mortal a Zaragoza". Se tratâ”œâ”‚ de una emotiva ceremonia oficiada por el seâ”œâ–’or canâ”œâ”‚nigo don Santiago Guallar y celebrada en la intimidad familiar, de la que todo el mundo fue informado con profusiâ”œâ”‚n de detalles por participar en ella notables personajes de la Espaâ”œâ–’a de la â”œآ®poca.', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53219502995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53219502995.webp', 'https://www.flickr.com/photos/zaragozaantigua/53219502995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23914, 'Plaza del Pilar 1905', 'Comercial escena capturada en el marco de la plaza del Pilar y centrada en un coche de recogida de ropas de la empresa "La Higiene de Zaragoza", Lavadero modelo mecâ”œأ­nico de Anechina y Compaâ”œâ–’â”œآ،a ubicado en el barrio de Ruiseâ”œâ–’ores, "primero y â”œâ•‘nico en Espaâ”œâ–’a de este sistema". Con una capacidad semanal de tratamiento de hasta 50.000 piezas, ofrecâ”œآ،a las mejores garantâ”œآ،as de higiene, perfecciâ”œâ”‚n, rapidez y economâ”œآ،a a la hora de tratar la limpieza mecâ”œأ­nica de las diversas prendas de ropa, desde los paâ”œâ–’uelos de bolsillo hasta las mantas grandes de lana. El buen desempeâ”œâ–’o de sus funciones permitiâ”œâ”‚ a esta empresa abrir pronto varias sucursales en la calle del Cinco de Marzo, la plaza de San Felipe y la calle de Roda.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65632000, -0.87877700, '0101000020E610000085436FF1F01EECBFF9DA334B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54330744919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54330744919.webp', 'https://www.flickr.com/photos/zaragozaantigua/54330744919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23915, 'Calle del Pilar 1942', 'Imagen capturada desde la altura de la calle de Juan Martâ”œآ،n Goicoechea y centrada en el lado de los impares de la calle del Pilar, con detalle del proceso de derribo de la casa-palacio del marquâ”œآ®s de Ayerbe sito en el nâ”œâ•‘mero 15 de ese vial. El despejado entorno de primer tâ”œآ®rmino es resultado de la demoliciâ”œâ”‚n integral previa de todos los edificios del lado de los pares de la calle del Pilar, asâ”œآ، como los de las manzanas delimitadas entre la plaza del Pilar y las calles de Latassa, Bayeu y Don Jaime I, todo como consecuencia de la prevista ejecuciâ”œâ”‚n de la uniâ”œâ”‚n de las plazas de La Seo y del Pilar. La casa-palacio de los Ayerbe fue derribada en el mes de mayo de ese aâ”œâ–’o, y en este caso la acciâ”œâ”‚n fue realizada por operarios municipales "con el fin de recoger cuidadosamente los materiales artâ”œآ،sticos" que pudiera contener, algo que fue muy bien valorado en la prensa de la â”œآ®poca, sin ninguna otra consideraciâ”œâ”‚n que realizar ante el derribo de este referencial palacio zaragozano que, como en otros tantos casos, fuese y no hubo nada. A la izquierda del solar palaciego, vista parcial de las viviendas seriadas que llegaban hasta el callejâ”œâ”‚n del Retiro Bajo del Pilar, entre las que se encontraba la antigua posada del Pilar. A la derecha, inmuebles que llegaban hasta el callejâ”œâ”‚n que las separaba de la Lonja, entre las que se encontraba la ribereâ”œâ–’a posada de los Reyes. Todas ellas fueron igualmente expropiadas y derribadas luego para conformar el espacio sobre el que, mâ”œأ­s tarde, emprender la construcciâ”œâ”‚n de la nueva Casa Consistorial.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65601800, -0.87751000, '0101000020E6100000F836FDD98F14ECBF2ECBD765F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54705272758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54705272758.webp', 'https://www.flickr.com/photos/zaragozaantigua/54705272758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24012, 'Plaza del Pilar 1975', 'Mayo es el mes de las flores, y en Zaragoza, ademâ”œأ­s, era el de las Fiestas de Primavera, de las Majas Internacionales, y de la cuestaciâ”œâ”‚n para subnormales. El holismo sistâ”œآ®mico de la ciudad parece ilimitado, como el universo, y amable, como sus canâ”œâ”‚nigos. A la derecha, el Pilar. Al fondo, Goya nos mira de reojo. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65660300, -0.87931200, '0101000020E61000000B5F5FEB5223ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24171100959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24171100959.webp', 'https://www.flickr.com/photos/zaragozaantigua/24171100959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24051, 'Pl. del Pilar 1903', 'Foto: Manuel Olivar. Procesiâ”œâ”‚n de la Virgen en la plaza del Pilar, con la calle de Alfonso I al fondo a la derecha, en los actos de inauguraciâ”œâ”‚n de las obras de construcciâ”œâ”‚n de la segunda de las torres del templo, el 19 de marzo de 1903. Serâ”œأ­ terminada en 1907. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65617300, -0.87839300, '0101000020E6100000682101A3CB1BECBF55C2137AFDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31448748770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31448748770.webp', 'https://www.flickr.com/photos/zaragozaantigua/31448748770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24084, 'Calle Alfonso 1916', 'Foto: Sâ”œأ­nchez Româ”œأ­n. Salida de la calle de Alfonso I a la plaza del Pilar de la comitiva de la Cruz Roja postulante para los perjudicados por la tormenta que desbordâ”œâ”‚ los râ”œآ،os de la comarca de Torrijo y Ateca a finales de julio de 1916, ocasionando numerosas muertes y daâ”œâ–’os. A la izquierda, mercerâ”œآ،a de Telesforo Garcâ”œآ،a, en el edificio del pasaje de la Industria y el Comercio. Fuente: Revista Blanco y Negro, 6-8-1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65607700, -0.87917400, '0101000020E6100000C9CA2F833122ECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42703534905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42703534905.webp', 'https://www.flickr.com/photos/zaragozaantigua/42703534905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24114, 'Plaza del Pilar 1908', 'Imagen capturada en la plaza del Pilar durante la visita del rey Alfonso XIII el dâ”œآ،a 14 de junio de ese aâ”œâ–’o para asistir a diversos eventos relacionados con el primer centenario del asedio francâ”œآ®s de 1808. En este caso se trata de la llegada de la comitiva, tras su arribo a la estaciâ”œâ”‚n de Campo Sepulcro, al exterior del templo del Pilar para asistir a solemne misa y Te Deum cantado. Bajo un sol bochornoso, anuncio de tormenta, el coche de caballos aparece estacionado ante la Puerta Baja del templo, donde un grupo de sâ”œâ•‘bditos aguardan expectantes al real visionado.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65623200, -0.87826200, '0101000020E6100000C539EAE8B81AECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52081345377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52081345377.webp', 'https://www.flickr.com/photos/zaragozaantigua/52081345377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24223, 'Plaza del Pilar 1952', 'Con el pertinente permiso de la autoridad competente, el piloto-paracaidista inglâ”œآ®s James Will se lanzâ”œâ”‚ en paracaâ”œآ،das desde la casa del Marquâ”œآ®s de Ayerbe que alberga el pasaje de la Industria y el Comercio o El Ciclâ”œâ”‚n, el dâ”œآ،a grande de las fiestas del Pilar. A la derecha, calle de Alfonso I. Al fondo y a la izquierda, fachada en obras de la nueva Casa consistorial. Fuente visual: foto Miguel Marâ”œآ،n Chivite.', 1952, 1952, 1952, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65601400, -0.87905100, '0101000020E6100000DC8310902F21ECBFECDB4944F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15929882955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15929882955.webp', 'https://www.flickr.com/photos/zaragozaantigua/15929882955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24225, 'Ofrenda de flores 1958', 'Aunque ya en 1939, con motivo de la victoria del bando fascista en la Guerra Civil, se organizâ”œâ”‚ en Zaragoza una manifestaciâ”œâ”‚n oficial con paseâ”œآ،llo de personas ataviadas con trajes regionales y provistas de flores para agradecer a la Virgen del Pilar la derrota del comunismo, no fue hasta 1958 cuando se regularizâ”œâ”‚ el ritual como "ofrenda de flores", que se venâ”œآ،a realizando sin mayor organizaciâ”œâ”‚n desde 1953. El acto, que ha tenido una participaciâ”œâ”‚n creciente, consiste en ataviar con manto floral una reproducciâ”œâ”‚n de la Virgen, tras desfilar por distintas calles de la ciudad. Estâ”œأ­ inspirado en ritos similares levantinos. El Ayuntamiento sufragâ”œâ”‚ las flores hasta 1986. En 1998 se cambiâ”œâ”‚ su ubicaciâ”œâ”‚n para llevarlo a una pirâ”œأ­mide metâ”œأ­lica, a sugerencia del cineasta Bigas Luna. En la imagen, miembros de la Agrupaciâ”œâ”‚n Artâ”œآ،stica Aragonesa bailan la jota durante la primera ofrenda oficializada, en la que participaron unas 2.000 personas. Fuente: "Zaragoza y sus fiestas".', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19723056288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19723056288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19723056288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24229, 'Plaza del Pilar 1953', 'Imagen capturada en el punto donde la calle de Alfonso I desemboca en la plaza del Pilar durante las homâ”œâ”‚nimas fiestas de principios del mes de octubre, como ilustra la notable profusiâ”œâ”‚n de banderas y gallardetes con los colores de la bandera nacional. Al fondo, fachada del templo con el aspecto tras la intervenciâ”œâ”‚n que a mediados de la dâ”œآ®cada anterior le confiriâ”œâ”‚ la gran galerâ”œآ،a decorativa de estatuas. La plaza todavâ”œآ،a presenta los â”œأ­rboles que caracterizaban este espacio, poco antes de ser arrancados.', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65606400, -0.87929200, '0101000020E6100000444DF4F92823ECBF9E0AB8E7F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23692412890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23692412890.webp', 'https://www.flickr.com/photos/zaragozaantigua/23692412890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24240, 'Ofrenda de Flores c.1962', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 40 de la calle de Alfonso I, chaflanero con la plaza del Pilar, y centrada en el paâ”œâ–’o central de la fachada principal del homâ”œâ”‚nimo templo durante la ceremonia de la tradicional, desde 1958, Ofrenda de Flores. En el momento de realizar esta imagen, el Nuncio de Su Santidad (por ausencia del arzobispo Casimiro Morcillo Gonzâ”œأ­lez, desplazado a Roma por el Concilio Vaticano II), rodeado de autoridades militares, religiosas e institucionales, oficia una ceremonia junto a la carroza de plata realizada en 1933 por Jorge Albareda que soporta un icono mariano tambiâ”œآ®n en plata realizado en el primer tercio del siglo XVII, y que de forma llamativa figura sin el niâ”œâ–’o en brazos, como era tradiciâ”œâ”‚n en aquellos tiempos, coetâ”œأ­neos con el desaparecido templo mudâ”œآ®jar de Santa Marâ”œآ،a del Pilar.', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65652900, -0.87874500, '0101000020E6100000ADC090D5AD1EECBF13F06B2409D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49317468018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49317468018.webp', 'https://www.flickr.com/photos/zaragozaantigua/49317468018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24863, 'Plaza del Pilar 1949', 'Carro de tracciâ”œâ”‚n asnal en la plaza del Pilar. A la izquierda, obras de construcciâ”œâ”‚n del Ayuntamiento. Al fondo, la Lonja y la Seo. Fuente: www.facebook.com/photo.php?fbid=10211232610224662&set...', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65606100, -0.87808200, '0101000020E6100000C899266C3F19ECBF2D978DCEF9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33051351094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33051351094.webp', 'https://www.flickr.com/photos/zaragozaantigua/33051351094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24882, 'Manzana Casas Plaza del Pilar 1885', 'Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n. (1885). Nueva manzana de casas en la Plaza del Pilar, esquina a la calle de Alfonso I, propiedad del Sr. Marquâ”œآ®s de Ayerbe.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65598400, -0.87900200, '0101000020E610000081CB63CDC820ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877551375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877551375.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877551375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24912, 'Ayuntamiento 1955', 'Las obras del edificio del Ayuntamiento se prolongaron durante dos dâ”œآ®cadas, de 1946 a 1965. En la foto, estado de la fachada aâ”œâ•‘n con mucho por construir. Fuente: www.delcampe.net', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65613500, -0.87759800, '0101000020E6100000C91EA1664815ECBF67614F3BFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21648452989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21648452989.webp', 'https://www.flickr.com/photos/zaragozaantigua/21648452989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25054, 'Franco y seâ”œâ–’ora 1961', 'Ayuntamiento de Zaragoza/Foto LOZANO. Setiembre 1961. El V Congreso Eucarâ”œآ،stico Nacional tuvo lugar en Zaragoza del 17 al 24 de setiembre de 1961. El Jefe del Estado y su seâ”œâ–’ora acudieron a presidir la ceremonia de clausura. En la imagen, ambos dos seres en el espacio a ellos reservado en la ceremonia, que tuvo lugar en la Plaza del Pilar, donde se rindiâ”œâ”‚ homenaje a Jesâ”œâ•‘s Sacramentado.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740980628.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740980628.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740980628/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25061, 'Borbâ”œâ”‚n y Borbâ”œâ”‚n 1970', '"1970 Zaragoza.- El Prâ”œآ،ncipe Juan Carlos, acompaâ”œâ–’ado del Infante Felipe ataviado con un traje de maâ”œâ–’o, saluda al pâ”œâ•‘blico congregado que asiste a la tradicional ofrenda floral a la Virgen del Pilar con motivo de su festividad." Efe / Y.V.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65640400, -0.87866500, '0101000020E61000009279E40F061EECBF577BD80B05D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934936241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934936241.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934936241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25075, 'Eva Perâ”œâ”‚n 1947', 'Foto: Luis Mompel. Marâ”œآ،a Eva Duarte de Perâ”œâ”‚n, "Evita", fue una actriz y polâ”œآ،tica argentina. En 1946 se convirtiâ”œâ”‚ en primera dama, por estar casada con Juan Domingo Perâ”œâ”‚n, y llegâ”œâ”‚ a ser un personaje muy popular. En 1947 realizâ”œâ”‚ una gira mundial, visitando Espaâ”œâ–’a en junio. El 21 de ese mes estuvo en Zaragoza. En la foto, acompaâ”œâ–’ada de militares y eclesiâ”œأ­sticos (alguien parecido a Nosfetaru asoma a su derecha), reza ante la Virgen del Pilar. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1947, 1947, 1947, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65621500, -0.87731900, '0101000020E6100000001AA54BFF12ECBF841266DAFED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20957798973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20957798973.webp', 'https://www.flickr.com/photos/zaragozaantigua/20957798973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25101, 'Corporaciâ”œâ”‚n 1991', 'Posado oficial en las escaleras de la Planta Noble del Ayuntamiento de la nueva Corporaciâ”œâ”‚n emanada de las elecciones municipales del 26 de mayo de 1991. En el centro y primera fila, Antonio Gonzâ”œأ­lez Triviâ”œâ–’o, que repite como alcalde tras alcanzar el PSOE hasta 15 concejalâ”œآ،as (tuvo 13 en 1987). El Partido Popular logrâ”œâ”‚ 7 (tuvo 5 en 1987), el Partido Aragonâ”œآ®s Regionalista 6 (tuvo 8 en 1987), y Convergencia Alternativa de Aragâ”œâ”‚n-Izquierda Unida 3 (tuvo 2 en 1987). Desapareciâ”œâ”‚ de escena el Centro Democrâ”œأ­tico y Social, que se presentâ”œâ”‚ a las elecciones teniendo 3 concejalâ”œآ،as.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65623200, -0.87732900, '0101000020E6100000E4A25A441413ECBF5A4B0169FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50379198927.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50379198927.webp', 'https://www.flickr.com/photos/zaragozaantigua/50379198927/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25571, 'Plaza del Pilar 1959', 'Aâ”œآ®rea visual panorâ”œأ­mica centrada en la nueva y gran plaza del Pilar con el fondo del râ”œآ،o Ebro, la arboleda de Macanaz y el barrio del Arrabal. Los cuatro nuevos espacios que componâ”œآ،an la plaza aparecen definidos, el mâ”œأ­s norteâ”œâ–’o, por la Cruz del Altar de la Patria inaugurado finalmente en 1954, y un bosquecillo de cipreses visible en buena parte por el solar donde estaba previsto construir los nuevos juzgados de la ciudad; en el centro, la plaza del Pilar de toda la vida, recayente al homâ”œâ”‚nimo templo, cuyas dos torres ribereâ”œâ–’as siguen en construcciâ”œâ”‚n; el tercer espacio, ordenado entre la nueva Casa Consistorial en construcciâ”œâ”‚n, y el aâ”œâ•‘n previsto desemboque del prolongado paseo de la Independencia; finalmente y en la parte inferior derecha, el tramo correspondiente a la Lonja En la parte superior y a la izquierda, la Pasarela Peatonal de Macanaz..', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65640100, -0.87892700, '0101000020E6100000D84812842B20ECBFE607AEF204D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50154232697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50154232697.webp', 'https://www.flickr.com/photos/zaragozaantigua/50154232697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25979, 'Plaza del Pilar 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Setiembre 1974. Vista aâ”œآ®rea, desde la altura de los tejados de las câ”œâ•‘pulas del Pilar, de la Plaza de las catedrales, la calle Alfonso, y la plaza del Gobierno Civil. A la derecha, la Seo y un fondo de cielo que deja ver, entre otros elementos, la Magdalena, el Hâ”œأ­bitat 2000, San Carlos Borromeo, San Pedro Nolasco, San Gil...', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65632400, -0.87877500, '0101000020E6100000575BB1BFEC1EECBF3ACAC16C02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15214570736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15214570736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15214570736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26039, 'Vista aâ”œآ®rea del Pilar 1957', 'Vista aâ”œآ®rea centrada en la plaza del Pilar. Al fondo, la margen izquierda del râ”œآ،o Ebro. Abajo a la derecha, la torre de la Seo. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65658000, -0.87874300, '0101000020E610000080D8D2A3A91EECBF959A3DD00AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31243176661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31243176661.webp', 'https://www.flickr.com/photos/zaragozaantigua/31243176661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26080, 'El Pilar 1938', 'Imagen capturada un dâ”œآ،a nublado desde un aeroplano modelo Heinkel 45-F 2 "Pavo" de la Legiâ”œâ”‚n Câ”œâ”‚ndor, radicado en el aerâ”œâ”‚dromo Sanjurjo, en funciones de reconocimiento sobrevuela el casco antiguo de la ciudad y centra su objetivo fotogrâ”œأ­fico en el templo del Pilar. En primer tâ”œآ®rmino, desemboque de la calle de Alfonso I en la arbolada plaza del Pilar, donde destaca a la izquierda, tras el Retiro Alto, la gran casona que fuera palacio de los marqueses de Aytona o de Medinacelli. De fondo, el râ”œآ،o Ebro, la arboleda de Macanaz y el Arrabal.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65602400, -0.87926000, '0101000020E61000006DCA15DEE522ECBF10B22C98F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54188362826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54188362826.webp', 'https://www.flickr.com/photos/zaragozaantigua/54188362826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20902, 'Plaza del Pilar 1990', 'Vista de las cimentaciones y otras estructuras de un gran templo romano halladas en 1990 ante el Ayuntamiento, durante la remodelaciâ”œâ”‚n de la plaza del Pilar. Era justa y necesaria su destrucciâ”œâ”‚n, para poder excavar un gran aparcamiento subterrâ”œأ­neo. Por ello, las autoridades ocultaron a la ciudadanâ”œآ،a el hallazgo. La prospecciâ”œâ”‚n durâ”œâ”‚ del 14 de mayo al 1 de junio. Dos aâ”œâ–’os despuâ”œآ®s, un informe del arqueâ”œâ”‚logo Josâ”œآ® Delgado hizo pâ”œâ•‘blica la jugarreta perpetrada por el alcalde Antonio Gonzâ”œأ­lez Triviâ”œâ–’o y su equipo de presuntos corruptos del PSOE. Al fondo a la derecha, el edificio El Ciclâ”œâ”‚n. En la imagen, restos de la cimentaciâ”œâ”‚n y parte del pâ”œâ”‚dium de un gran templo romano del siglo I, bastante alejado del Foro de Caesaraugusta, lo cual unido a que tenâ”œآ،a una orientaciâ”œâ”‚n eje E-O (entrada por el este), harâ”œآ،a pensar en la posible convivencia de dos foros conectados. En el presente caso, posiblemente se trataba del templo tetrâ”œأ­stilo de columnas corintias con acanaladuras que aparece en numerosas monedas acuâ”œâ–’adas en Caesaraugusta.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65584400, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32273657101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32273657101.webp', 'https://www.flickr.com/photos/zaragozaantigua/32273657101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20975, 'Calle Don Jaime I 1857', '"Carrretera General de Barcelona. Proyecto de travesâ”œآ،a por la ciudad de Zaragoza", plano de Josâ”œآ® de Echeverrâ”œآ،a, 1857. El conjunto de calles estrechas que llevaban del Puente de Piedra al Coso Medio tenâ”œآ،a los dâ”œآ،as contados en 1857: fue el aâ”œâ–’o en que se empezâ”œâ”‚ a derribar para prolongar la calle de San Gil hasta el Ebro, con diferentes excusas, como la esgrimida como tâ”œآ،tulo de este plano. A partir de 1860, la vâ”œآ،a se denominarâ”œآ،a Don Jaime I, hasta hoy, que muchos zaragozanos la siguen llamando San Gil, siglo y medio despuâ”œآ®s. Fuente: AMZ.', 1857, 1857, 1857, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65425200, -0.87761800, '0101000020E610000090300C587215ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19880597199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19880597199.webp', 'https://www.flickr.com/photos/zaragozaantigua/19880597199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20996, 'Calle Mayor c.1855', '[Casa de Manuel Esmir en Zaragoza]. Dibujo realizado por Valentâ”œآ،n Carderera y Solano del patio interior de la casa de Manuel Esmir (posiblemente construida en los siglos XV-XVI), que era utilizada como mesâ”œâ”‚n y posada de Santa Ana, en la calle Mayor. Esta casa fue derribada hacia 1862, y parece ser que algunas de sus columnas fueron reutilizadas en el palacio de los duques de Villahermosa en Pedrola, durante unas reformas. Fuente visual: Biblioteca Nacional de Espaâ”œâ–’a, bdh.bne.es/ Signatura: DIB/18/1/7882', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65524800, -0.87910800, '0101000020E6100000ECDCB419A721ECBF7C629D2ADFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33944184106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33944184106.webp', 'https://www.flickr.com/photos/zaragozaantigua/33944184106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21077, 'Palacio de Osera 1871', '"Proyecto de reparaciâ”œâ”‚n y decorado de la casa nâ”¬â•‘ 142 de la calle de la Manifestaciâ”œâ”‚n, propiedad de D. Calisto Loubet", plano alzado de la fachada del antiguo palacio de Osera de Zaragoza, segâ”œâ•‘n proyecto del arquitecto Pedro Esteban y Romeo, 8 de agosto de 1871. En la imagen, a la izquierda, "Estado actual"; a la derecha, "Reforma". El de Osera es un ejemplo de palacio renacentista zaragozano desaparecido. Su acceso se encontraba a la altura del actual nâ”œâ•‘mero 26 de la calle de Espoz y Mina, junto a la iglesia de Santa Cruz, con la que compartâ”œآ،a medianeras. Fue construido entre 1510 y 1515 como vivienda de Gaspar de Ariâ”œâ–’o, familia que obtuvo el marquesado de Osera en 1634. Tras sucesivas reformas, como la de 1871, que modificâ”œâ”‚ el aspecto de la tercera planta, fue derribado en 1963. Sus â”œâ•‘ltimos usos lo asocian a Acciâ”œâ”‚n Social Catâ”œâ”‚lica y la Caja de Ahorros de la Inmaculada, llegando a tener un amplio salâ”œâ”‚n de actos para representaciones teatrales en el gran espacio que ocupaba hacia la plaza de Santa Cruz. En las techumbres de sus salas principales contaba con ricos artesonados mudâ”œآ®jares de madera, que fueron trasladados al Ayuntamiento de Zaragoza, terminado en 1965 en la Plaza del Pilar 18. Hoy continâ”œâ•‘an adornando el techo del Salâ”œâ”‚n de Sesiones, del Salâ”œâ”‚n de Comisiones y del despacho del Alcalde. Su patio principal estâ”œأ­ reconstruido mediante sus cuatro columnas originales en la antigua casa de GIl Gonzâ”œأ­lez Marcilla, desde 1984 discoteca Torreluna. Fuente: "La casa de Gaspar de Ariâ”œâ–’o y las techumbres mudâ”œآ®jares de Zaragoza", Rafael Chiribay, DGA, 1999.', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65440400, -0.87803700, '0101000020E6100000C8B1F50CE118ECBF902FA182C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22181043502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22181043502.webp', 'https://www.flickr.com/photos/zaragozaantigua/22181043502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21143, 'Iglesia de Santiago c.1890', 'En la confluencia de las calles de la Cuchillerâ”œآ،a y Santiago se levantaba la iglesia de Santiago, de origen româ”œأ­nico. Allâ”œآ، se reunâ”œآ،a el Concejo (Ayuntamiento) hasta la construcciâ”œâ”‚n de las Casas de la Puente en el siglo XIII. Fue derribada entre 1911 y 1913. En el edificio actual, Don Jaime I 39, una Cruz de Santiago recuerda la ubicaciâ”œâ”‚n y la fecha de la construcciâ”œâ”‚n del inmueble construido en su lugar (1915-1916). La advocaciâ”œâ”‚n al santo fue trasladada a la iglesia del antiguo convento de San Ildefonso. En la imagen se atisban restos del antiguo pâ”œâ”‚rtico. Fuente visual: "Restos bizantinos (sic) de la iglesia de Santiago", fototipia de Joarizti y Mariezcurrena, en Zaragoza artâ”œآ،stica, monumental â”œآ® histâ”œâ”‚rica, por A. y P. Gascâ”œâ”‚n de Gotor.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65469800, -0.87726900, '0101000020E61000008F6D19709612ECBFD960E124CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14906230637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14906230637.webp', 'https://www.flickr.com/photos/zaragozaantigua/14906230637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21298, 'Calle Santa Cruz 1903', '"Fachada de la Casa del Canal y oficinas de obras pâ”œâ•‘blicas". Fotografâ”œآ،a publicada con motivo de la visita a Zaragoza del rey Alfonso XIII, en octubre de 1903. Al fondo, casa Tarâ”œآ،n o del Canal. A la derecha, esquina del palacio de los Francos de Villalba, cuyo derribo dio lugar a la plaza de Santa Cruz. Fuente: Revista La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65428100, -0.87890800, '0101000020E6100000282B86AB0320ECBF74B2D47ABFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32356687532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32356687532.webp', 'https://www.flickr.com/photos/zaragozaantigua/32356687532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22460, 'Universidad 1960', 'Imagen aâ”œآ®rea capturada sobre el entorno del despejado campus universitario de la plaza de San Francisco, con los pabellones de las facultades de Filosofâ”œآ،a y Letras, Ciencias, y Derecho, el Colegio Mayor Pedro Cerbuna, y la gran pista de atletismo, trazada sobre la antigua carretera de Valencia, que ahora se derivarâ”œآ،a por la nueva calle de Don Juan Bosco, a la izquierda. A la derecha, e inmediato, el cuartel de artillerâ”œآ،a de Palafox, cuya antigua pista de equitaciâ”œâ”‚n todavâ”œآ،a aparece delimitada dentro del nuevo reciento universitario, y los dos grandes bloques de viviendas frente a los que se destacan las nuevas instalaciones de "La Hâ”œآ،pica". Al fondo, y tras la Ciudad Jardâ”œآ،n, y las traseras de la calle de Corona de Aragâ”œâ”‚n, la ciudad. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64036700, -0.90232200, '0101000020E610000011C30E63D2DFECBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31942081996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31942081996.webp', 'https://www.flickr.com/photos/zaragozaantigua/31942081996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21462, 'Calle de Espoz y Mina 1915', 'Inâ”œآ®dita imagen capturada desde la calle de Don Jaime I y orientada hacia el tramo final de la calle de Espoz y Mina que desemboca en ella. A la izquierda, el antiguo inmueble del nâ”¬â•‘ 46 que poco despuâ”œآ®s serâ”œآ،a derribado junto con la vecina gran casa que fuera del conde de Atarâ”œآ®s y en cuyo solar serâ”œآ،a construida la moderna casa de los Marâ”œآ،n Corralâ”œآ® proyectada por el arquitecto Francisco Albiâ”œâ–’ana. En el nâ”¬â•‘ 36 se abre el ingreso principal a la gran casa de los Osera, y poco despuâ”œآ®s destaca la sobria fachada de la neoclâ”œأ­sica iglesia de la Santa Cruz, en el recoleto tramo de la calle donde confronta con la antigua casa de Aguilar o Pardo. A la derecha, traseras del palacio de Montemuzo y tras ellas los inmuebles de los nâ”œâ•‘meros 35-41 que tiempo despuâ”œآ®s serâ”œآ،an retranqueados. La circulaciâ”œâ”‚n rodada se presenta en el formato de carro a tracciâ”œâ”‚n de sangre, mientras una caballerâ”œآ،a montada se encamina a Don Jaime I, donde en primer tâ”œآ®rmino y entre el adoquinado destacan las vâ”œآ،as por las que transitan los coches de las lâ”œآ،neas Arrabal y Gâ”œأ­llego.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65432400, -0.87773600, '0101000020E61000000BB3D0CE6916ECBF747E8AE3C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52428359237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52428359237.webp', 'https://www.flickr.com/photos/zaragozaantigua/52428359237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21473, 'Don Jaime I 1917', 'Imagen capturada durante la construcciâ”œâ”‚n del esquinero inmueble que ocupa el solar de los nâ”œâ•‘meros 47-49 de la calle de Don Jaime I y los nâ”œâ•‘meros 44-46 de la calle de Espoz y Mina (numeraciâ”œâ”‚n luego modificada). Fue proyectado en 1916 por el arquitecto (y en ese momento tambiâ”œآ®n concejal republicano) Francisco Albiâ”œâ–’ana Corralâ”œآ® para los doctores â”œأ¼ngel y Vâ”œآ،ctor Marâ”œآ،n Corralâ”œآ®, que lo destinaron al alquiler de viviendas y tiendas, reservâ”œأ­ndose la planta noble donde habilitar consulta profesional. El antiguo inmueble (gran casona que fuera del conde de Atarâ”œآ®s) fue desalojado de sus inquilinos y autorizado a ser derribado a finales de 1916, coincidiendo en el tiempo con la finalizaciâ”œâ”‚n del derribo de la vecina iglesia de Santiago. Al fondo de la imagen, medianera con el colindante edificio del nâ”œâ•‘mero 42 de la calle de Espoz y Mina.', 1917, 1917, 1917, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65426000, -0.87767200, '0101000020E61000005CAD1397E315ECBF5D8AABCABED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54167493986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54167493986.webp', 'https://www.flickr.com/photos/zaragozaantigua/54167493986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21527, 'Casa de los Tarâ”œآ،n c.1924', 'La parroquia de la Exaltaciâ”œâ”‚n de la Santa Cruz tenâ”œآ،a un carâ”œأ­cter estamentalmente muy exclusivo y nobiliario. En su jurisdicciâ”œâ”‚n se levantaron una notable cantidad de palacios y casas solariegas, como la de la familia de los Tarâ”œآ،n, que proveyâ”œâ”‚ al Reino de hasta dos medievales Justicias. En el siglo XVI esta familia levantâ”œâ”‚ una gran casa segâ”œâ•‘n las formas y maneras de la italiana moda renacentista, centrando la construcciâ”œâ”‚n en torno a un gran patio al que se accedâ”œآ،a desde la calle por un portalâ”œâ”‚n que permitâ”œآ،a el paso a caballerâ”œآ،as y carruajes. Este edificio fue luego remodelado intensamente, en varias ocasiones. En 1706 devino en sede del Tribunal de la Santa Inquisiciâ”œâ”‚n, cuando â”œآ®sta fue desahuciada de la Aljaferâ”œآ،a por el borbâ”œâ”‚n Felipe. Aquâ”œآ، estuvo hasta 1759. Unos pocos aâ”œâ–’os despuâ”œآ®s, en 1765, la Casa fue reformada en las formas dieciochescas del momento: su fachada fue enfoscada, y se abriâ”œâ”‚ una segunda puerta de acceso, en piedra, y formas netamente neoclâ”œأ­sicas. En la imagen, detalle de esta puerta. Fuente visual: "Una mirada a travâ”œآ®s de la arquitectura: Regino y Josâ”œآ® Borobio Ojeda", Daniel Estabâ”œآ®n Boldova.', 1924, 1924, 1924, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17126822342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17126822342.webp', 'https://www.flickr.com/photos/zaragozaantigua/17126822342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21556, 'Calle Jordâ”œأ­n de Urriâ”œآ®s 1929', 'Acto oficial de descubrimiento de la lâ”œأ­pida que daba el nombre del fallecido capitâ”œأ­n de Regulares de Ceuta, Ramâ”œâ”‚n Jordâ”œأ­n de Urriâ”œآ®s, a la antigua calle del Clavel. Hijo del marquâ”œآ®s de Velilla de Ebro, en 1924 fue herido en los combates de la posiciâ”œâ”‚n de Coba-Darsa, durante la guerra colonial en el Protectorado de Marruecos, y muriâ”œâ”‚ a los pocos dâ”œآ،as. Este homenaje se producâ”œآ،a en los â”œâ•‘ltimos momentos de la Dictadura de Primo de Rivera, mâ”œأ­s de cinco aâ”œâ–’os despuâ”œآ®s de los hechos referidos. Fuente visual: "Mundo Grâ”œأ­fico" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65466800, -0.87720100, '0101000020E61000008597E0D40712ECBF6EDE3829CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21406598513.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21406598513.webp', 'https://www.flickr.com/photos/zaragozaantigua/21406598513/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21560, 'Arco de los Cartujos 1929', '"Zaragoza. Arco de los Cartujos. Estilo: Ojival [o Gâ”œâ”‚tico]". Imagen del antiguo arco de los Cartujos desde la calle Bayeu, en el tramo entre Goicoechea (a la espalda), y Santiago (delante). Al fondo, la calle de Espoz y Mina. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65518400, -0.87815400, '0101000020E61000002D40DB6AD619ECBF656EBE11DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22358490544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22358490544.webp', 'https://www.flickr.com/photos/zaragozaantigua/22358490544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21615, 'Espoz y Mina 1921', 'Con la venia y bendiciâ”œâ”‚n del cardenal-arzobispo Juan Soldevila y Romero, fue organizada en Zaragoza la asamblea general del partido carlista-jaimista (por Jaime de Borbâ”œâ”‚n y Borbâ”œâ”‚n-Parma, pretendiente carlista al trono de Espaâ”œâ–’a) Comuniâ”œâ”‚n Tradicionalista. Efectivamente, el primer acto del programa fue una tradicional misa y comuniâ”œâ”‚n general en el Pilar, que dio paso a tres intensos dâ”œآ،as de discusiones polâ”œآ،ticas en la sede del Câ”œآ،rculo Jaimista local, en la calle Espoz y Mina. En la imagen, un grupo de asambleâ”œآ،stas posa tras las autoridades (terrenales) del partido, encabezadas por el secretario polâ”œآ،tico Josâ”œآ® Selva Mergelina, marquâ”œآ®s de Villores, en el patio trasero de la sede Jaimista, un dâ”œآ،a de sol, y buen tiempo. Fuente visual: foto Miguel Marâ”œآ،n Chivite, en revista "La Hormiga de Oro".', 1921, 1921, 1921, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65505600, -0.87946200, '0101000020E61000005E64027E8D24ECBF388600E0D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31798357243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31798357243.webp', 'https://www.flickr.com/photos/zaragozaantigua/31798357243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21638, 'Calle de San Voto c.1922', 'Imagen del patio central de la gran casa del siglo XVII esquinera entre las calles de San Fâ”œآ®lix y San Voto, reciâ”œآ®n reformada por Pascual Bravo Sanfeliu para habilitarla como sede del Sindicato Central de Aragâ”œâ”‚n. El chorro de luz natural que entra por el patio ilumina cenitalmente la oficina de atenciâ”œâ”‚n al pâ”œâ•‘blico instalada en â”œآ®l.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65396400, -0.87868000, '0101000020E6100000E7C6F484251EECBF7461A417B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50826773013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50826773013.webp', 'https://www.flickr.com/photos/zaragozaantigua/50826773013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21670, 'Vista parcial c.1932', 'Foto aâ”œآ®rea del Pilar y su entorno.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65569200, -0.87928300, '0101000020E610000078B81D1A1623ECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728687219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728687219.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728687219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22525, 'Polâ”œآ،gono Romareda 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/setiembre 1970. El "Plan Parcial de la Gran Vâ”œآ،a" (1961) estaba cobrando forma a pocos metros del campo municipal de la Romareda. Promovido por el Ministerio de la Vivienda, actuaba sobre 29 hectâ”œأ­reas, en las que levantar 2224 viviendas agrupadas en cooperativas de funcionarios y empleados, como "Santa Rita", "Peritos Industriales", "San Cristâ”œâ”‚bal", "Espejo de Justicia"... asâ”œآ، hasta 33. Junto con las viviendas, estaban previstas zonas verdes y todos los servicios posibles. En cuanto al nombre del polâ”œآ،gono, en principio estaba previsto "Barrio de la Paz", aunque oficialmente su etiqueta era "Polâ”œآ،gono Gran Vâ”œآ،a". Pues ni una cosa ni otra, porque ya en Torrero existâ”œآ،a la barriada de la Paz (modesta, pero digna), y la Gran Vâ”œآ،a conservaba reminiscencias de mâ”œأ­s poderâ”œآ،o econâ”œâ”‚mico. Terminarâ”œأ­ adoptando, por extensiâ”œâ”‚n, el de la acequia que por estos lares fluâ”œآ،a de antiguo: Romareda. En la imagen, tomada desde las alturas del nâ”¬â•‘ 5 de la calle S. Francisco de Borja (1962), una panorâ”œأ­mica de buena parte del Polâ”œآ،gono Romareda, en pleno frenesâ”œآ، constructivo. De momento, hormigâ”œâ”‚n, acero, ladrillos, y mucha mano de obra. Luego vendrâ”œأ­n las calles: Violante de Hungrâ”œآ،a (en primerâ”œآ،simo plano, de izquierda a derecha), Asâ”œآ،n y Palacios (justo enfrente), Luis Bermejo (el camino a mitad de imagen, de izquierda a derecha), Pedro III el Grande (paralelo, mâ”œأ­s hacia el fondo), Condes de Aragâ”œâ”‚n (derecha)... A la izquierda queda el recinto de la Feria de Zaragoza y el estadio Municipal de la Romareda. A la derecha, el solar donde se construirâ”œأ­ el Palacio de Deportes de Zaragoza, o "El Huevo". Las instalaciones educativas (pâ”œâ•‘blicas y privadas) se irâ”œأ­n encajando en los huecos, como la parroquia de Sta. Mâ”œâ”‚nica (1972). En cuanto a las zonas verdes, pues mejor ir al Parque Grande, que estâ”œأ­ bien cerca.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63954900, -0.90196200, '0101000020E610000017838769DFDCECBF4298DBBDDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665456160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665456160.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665456160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21857, 'Plza. San Braulio 1934', 'Imagen capturada en la angosta plazuela de San Braulio con motivo de la nocturna explosiâ”œâ”‚n de un artefacto durante la huelga general de treinta y cinco dâ”œآ،as entre los meses de abril-mayo de ese aâ”œâ–’o. El explosivo fue colocado junto al economato de consumo Cooperativa Militar y Civil, moderna construcciâ”œâ”‚n de 1931 sita a la izquierda de la imagen, edificio que perdura. Una pareja que casualmente saliâ”œâ”‚ de una vivienda de la calle Miguel de Molino, al fondo a la derecha, resultâ”œâ”‚ levemente afectada, asâ”œآ، como los cristales de las ventanas traseras de la gran sede de Comuniâ”œâ”‚n Tradicionalista en la calle de Espoz y Mina (a la derecha), que fuera sede local del carlista Câ”œآ،rculo Jaimista. El edificio objeto del atentado apenas sufriâ”œâ”‚ daâ”œâ–’os. En la imagen, fuerza del cuerpo de Seguridad y Asalto, y de la policâ”œآ،a, inspeccionan la zona y miran al reportero grâ”œأ­fico. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65481500, -0.87944100, '0101000020E6100000815EB8736124ECBF12F758FAD0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36108423460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36108423460.webp', 'https://www.flickr.com/photos/zaragozaantigua/36108423460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21921, 'Calle de Espoz y Mina 1939', 'Imagen capturada durante la matinal del â”œâ•‘ltimo dâ”œآ،a del "Aâ”œâ–’o de la Victoria" en la calle de Espoz y Mina a la altura de la parroquia de Santa Cruz (a la izquierda y fuera de plano), al paso de la gran cabalgata anunciadora de las fiestas del "XIX Centenario de la venida de la Virgen en carne mortal (sic) a Zaragoza". A la derecha y esquinera con la calle de Francisco Bayeu, la antigua casa del infanzâ”œâ”‚n Jerâ”œâ”‚nimo Câ”œâ”‚sida habilitada para albergar los muebleros Almacenes Moliner.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65454100, -0.87811200, '0101000020E6100000723447567E19ECBF1172DEFFC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54241826916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54241826916.webp', 'https://www.flickr.com/photos/zaragozaantigua/54241826916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21929, 'Nevada plaza de La Seo c.1944', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. (SF). Imagen de la Plaza del Pilar y de la Plaza de la Seo, tras una fuerte nevada.', 1944, 1944, 1944, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65558300, -0.87724300, '0101000020E610000040A374E95F12ECBF2368CC24EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14904139066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14904139066.webp', 'https://www.flickr.com/photos/zaragozaantigua/14904139066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22042, 'Casimiro Morcillo 1955', 'Foto Luis Mompel. El 5 de diciembre de 1955, Casimiro Morcillo pasea en mula por la plaza del Pilar, con la Seo al fondo y el Gobierno Civil a la derecha. Es su presentaciâ”œâ”‚n como nuevo arzobispo, tras la muerte de su predecesor, Rigoberto Domâ”œآ®nech. Durâ”œâ”‚ en su cargo hasta 1964, cuando fue llamado a presidir la nueva archidiâ”œâ”‚cesis de Madrid, nada menos. Hasta llegâ”œâ”‚ a ser presidente de la Conferencia Episcopal. Le sucediâ”œâ”‚ Pedro Cantero Cuadrado.', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65574300, -0.87804900, '0101000020E6100000D9226937FA18ECBF5CCAF962EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750529500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750529500.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750529500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22189, 'Calle de Alfonso I c.1950', 'Grandes almacenes textiles y de peleterâ”œآ،a La Campana de Oro, ubicados en la achaflanada esquina entre la calle de Alfonso I con la de Prudencio, a la izquierda, abiertos en 1885 y clausurados en 2013. Como ilustra la imagen, el carâ”œأ­cter comercial de esta calle venâ”œآ،a determinado, ademâ”œأ­s de por las tiendas en planta calle, por las ubicadas en los pisos superiores.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65580400, -0.87956200, '0101000020E610000040BD19355F25ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32210891574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32210891574.webp', 'https://www.flickr.com/photos/zaragozaantigua/32210891574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22293, 'Pl. del Pilar 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/12/1965. "Cuerpo de Infanterâ”œآ،a celebra la fiesta de la Inmaculada." Entre los actos festivos y celebraciones varias organizadas con motivo de la inauguraciâ”œâ”‚n de la nueva Casa Consistorial de la plaza del Pilar, se incluyeron tambiâ”œآ®n algunas actuaciones castrenses de recia virilidad y bravo ardor patrio. En la imagen, el â”œأ¼ngel Custodio, San Valero, y autoridades militares y civiles, en uno de los desfiles de ese aâ”œâ–’o, ante la puerta del Ayuntamiento. Quienes mejor se lo estaban pasando eran las seâ”œâ–’oras de la derecha extrema.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65587900, -0.87743600, '0101000020E610000065A88AA9F413ECBF0C91D3D7F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15358580566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15358580566.webp', 'https://www.flickr.com/photos/zaragozaantigua/15358580566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22349, 'Guardias c.1968', 'Foto â”œأ¼ngel Duerto. Grupo de guardias de trâ”œأ­fico de la policâ”œآ،a municipal de Zaragoza, ante el Ayuntamiento. Fuente: "El municipio en Aragâ”œâ”‚n", DPZ, 2004.', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65588700, -0.87781100, '0101000020E6100000B53522180717ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20354555718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20354555718.webp', 'https://www.flickr.com/photos/zaragozaantigua/20354555718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22668, 'Calle San Fâ”œآ®lix 1973', 'Calle de San Fâ”œآ®lix. Al fondo, el antiguo palacio de los Torrero y la calle de San Voto. A la derecha, muro que seâ”œâ–’ala el derribo del palacio de Ariâ”œâ–’o. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65385800, -0.87855300, '0101000020E61000009FAF592E1B1DECBF2E1D739EB1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23117995416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23117995416.webp', 'https://www.flickr.com/photos/zaragozaantigua/23117995416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22669, 'Calle San Voto 1973', 'Calle San Voto. En el centro, su entrada al palacio de los Torrero. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65393000, -0.87825200, '0101000020E6100000E2B034F0A31AECBFC8EF6DFAB3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23180093591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23180093591.webp', 'https://www.flickr.com/photos/zaragozaantigua/23180093591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22684, 'Calle de San Voto 1972', 'Imagen capturada en la plaza de Santa Cruz y centrada en el tramo de los pares de la calle de San Voto (antigua del Correo Viejo): de derecha a izquierda, los inmuebles de los nâ”œâ•‘meros 2, 4 y el 6-8, antiguo gran caserâ”œâ”‚n que albergâ”œâ”‚ el denominado "Hogar del Herido" creado por la Falange Espaâ”œâ–’ola Tradicionalista que conservaba junto a su ingreso una lâ”œأ­pida con inscripciâ”œâ”‚n que informaba del carâ”œأ­cter de la inmediata "Glorieta de la Santa Cruz" como "sâ”œآ،mbolo de la nueva Espaâ”œâ–’a, de nuestra Patria cristiana que resurge teniendo por guâ”œآ،a la Santa Cruz", y que concluâ”œآ،a con las rituales exclamaciones "â”¬أ­Arriba Espaâ”œâ–’a! â”¬أ­Viva Espaâ”œâ–’a!" Al fondo, traseras de la gran casona del nâ”¬â•‘ 31 de la calle de Don Jaime I, poco antes de su derribo que permitirâ”œآ،a duplicar el espacio de la recoleta plaza de Ariâ”œâ–’o (antigua plazuela de San Martâ”œآ،n y Atarâ”œآ®s) . Los referidos nâ”œâ•‘meros 2 y 4 de San Voto tambiâ”œآ®n serâ”œآ،an derribados aâ”œâ–’os despuâ”œآ®s, sustituidos por modernos inmuebles. Fuente visual: AMZ.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65404600, -0.87873300, '0101000020E61000009C4F1DAB941EECBF310A82C7B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26718541287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26718541287.webp', 'https://www.flickr.com/photos/zaragozaantigua/26718541287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22722, 'Museo Camâ”œâ”‚n Aznar 1979', 'Imagen de la renacentista casa de los Câ”œâ”‚sida y Albiâ”œâ”‚n en la antigua Calle Mayor que, tras numerosos avatares y usos polifacâ”œآ®ticos (incluso como Capitanâ”œآ،a General), a mediados de los aâ”œâ–’os 70 del siglo XX, camino de su aniversario 450, fue adquirida por una poderosa entidad local de ahorro. Rehabilitada bajo direcciâ”œâ”‚n de Regino Borobio, en 1979 fue abierta como "Museo de Humanidades Camâ”œâ”‚n Aznar", para albergar las colecciones de arte donadas por el matrimonio Josâ”œآ® Camâ”œâ”‚n Aznar-Marâ”œآ،a Luisa â”œأ¼lvarez. En la imagen, estado del restaurado patio y de la escalera de acceso a los pisos superiores, un poco antes de su apertura pâ”œâ•‘blica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65478000, -0.87829500, '0101000020E6100000B4B0A71DFE1AECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30304382276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30304382276.webp', 'https://www.flickr.com/photos/zaragozaantigua/30304382276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22754, 'Policâ”œآ،a motorizada 1977', 'Presentaciâ”œâ”‚n de la unidad motorista de la Policâ”œآ،a Municipal, ante el Ayuntamiento, en la celebraciâ”œâ”‚n de Nuestra Seâ”œâ–’ora del Portillo. Al fondo, entre brumas, la torre de la Seo. Fuente: Heraldo.es', 1977, 1977, 1977, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65583300, -0.87781600, '0101000020E610000027FA7C941117ECBF9C51F355F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32696414290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32696414290.webp', 'https://www.flickr.com/photos/zaragozaantigua/32696414290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22839, 'Salchichauto c.1981', 'En la furgoneta de la imagen, una DKW modelo "Vehâ”œآ،culo tienda" matriculada en 1946, conocida como "Salchichauto", Fâ”œآ®lix Hernâ”œأ­ndez Gonzâ”œأ­lez vendâ”œآ،a bocadillos de salchicha, refrescos y cervezas en la plaza del Pilar, junto al Gobierno civil, desde 1971. Esta tienda ambulante se trasladaba a diversas ubicaciones en funciâ”œâ”‚n de las posibilidades de negocio, como las ferias, la plaza de toros o el entorno de La Romareda, cuando allâ”œآ، se celebraban las pruebas prâ”œأ­cticas de los exâ”œأ­menes de conducir y los copazos de coâ”œâ–’ac y de "revueltillo" daban â”œأ­nimos extra a los examinandos.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65540000, -0.87825900, '0101000020E6100000815D4D9EB21AECBF32E6AE25E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896793825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896793825.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896793825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22865, 'Plaza de Santa Cruz 1987', 'Luis Mâ”œآ،nguez. 1987. Verde imagen de una plaza regida por la Cruz de hierro de Regino Borobio inaugurada en mayo de 1937, con la inscripciâ”œâ”‚n أ”أ‡آ£TRANSEUNTE. ESTA CRUZ BENDITA ESPERA DE TI UNA ORACION POR LOS MARTIRES DE LA GUERRA R.I.P.أ”أ‡أک A la izquierda, la "Casa del Canal", o Casa Tarâ”œآ،n. A la derecha, las traseras de la iglesia de la Exaltaciâ”œâ”‚n de la Santa Cruz, con visual parcial de su torre. La plaza se llama de la Santa Cruz, por si acaso.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665916418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665916418.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665916418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22880, 'Mâ”œأ­s Birras aâ”œâ–’os 80', 'Foto: Vicente Morcano, aâ”œâ–’os 80 del siglo XX. Instantâ”œأ­nea del grupo de rock zaragozano Mâ”œأ­s Birras (1985-1993) haciendo honor a su nombre. Su cantante, Mauricio Aznar (a la derecha) continuâ”œâ”‚ su carrera musical en solitario hasta su muerte en 2000. El Ayuntamiento le dedicâ”œâ”‚ una calle en el barrio de Casablanca. La foto estâ”œأ­ tomada en la plaza del Pilar de Zaragoza, frente al Ayuntamiento. En 2015 hay allâ”œآ، un solar. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65522700, -0.87839700, '0101000020E6100000C3F17C06D41BECBF643A747ADED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19298298371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19298298371.webp', 'https://www.flickr.com/photos/zaragozaantigua/19298298371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22948, 'Calle de Santiago 1985', 'Imagen parcial de la fachada de la gran casa del siglo XVI localizada en la calle de Santiago e inmediata a la iglesia homâ”œâ”‚nima, que a principios del siglo XIX habâ”œآ،a recaido en el marquesado de Montemuzo. Deshabitado y abandonado largo tiempo, a finales de 1984 el ayuntamiento acometiâ”œâ”‚ obras de consolidaciâ”œâ”‚n tras el hundimiento de la zona central y patio de la casa. La captura se corresponde con el resultado del apuntalamiento de la gran puerta de ingreso. A la derecha, el moderno edificio del nâ”œâ•‘mero 30-32 de la calle. En la primavera de 1985 la familia Latorre Montalvo, heredera patrimonial del inmueble, vendiâ”œâ”‚ el edificio al ayuntamiento, que tras una importante intervenciâ”œâ”‚n lo destinâ”œâ”‚ a sede del Archivo, Biblioteca y Hemeroteca municipales. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65492800, -0.87759600, '0101000020E61000009C36E3344415ECBF0A9E42AED4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38643880244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38643880244.webp', 'https://www.flickr.com/photos/zaragozaantigua/38643880244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22996, 'Pasaje El Ciclâ”œâ”‚n 1992', 'Imagen capturada en el interior del Pasaje del Comercio y de la Industria, realizado en 1882-1883 con diseâ”œâ–’o del arquitecto Fernando de Yarza como galerâ”œآ،a comercial en los bajos de la nueva manzana de viviendas delimitada por las calles de Alfonso I, plaza del Pilar, calle de Forment y de Santiago. La influencia estâ”œآ®tica francesa de la â”œآ®poca (Segundo Imperio) queda fijada mediante formas eclâ”œآ®cticas y configura uno de los mâ”œأ­s castizos espacios comerciales de la ciudad, tambiâ”œآ®n denominado "El Ciclâ”œâ”‚n" por los referenciales almacenes de la derecha. En 1998 fue restaurado y rehabilitado, y en 2008 iniciâ”œâ”‚ un proceso de revitalizaciâ”œâ”‚n que continâ”œâ•‘a, rompiendo asâ”œآ، la tendencia de lo sucedido con tantos otros pasajes comerciales por su extrema y desconsiderada cercanâ”œآ،a a la ciudad consolidada. La de la imagen es la galerâ”œآ،a comercial a la que se ingresa desde la calle de Santiago (al fondo) pasando bajo un forjado arco con la leyenda "Pasaje del Comercio". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65558500, -0.87887200, '0101000020E6100000F5D72B2CB81FECBFC45F9335EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23930140657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23930140657.webp', 'https://www.flickr.com/photos/zaragozaantigua/23930140657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23031, 'Plaza de Ariâ”œâ–’o 1992', 'Plaza de Ariâ”œâ–’o, en una vista tomada desde la calle de Don Jaime I. Al fondo, calle de San Voto, con el palacio renacentista de los Torrero, del siglo XVI, que alberga el Colegio de Arquitectos. A la derecha, sede de una entidad bancaria. En primer plano, fuente minimalista de hormigâ”œâ”‚n, en la lâ”œآ،nea de las llamadas أ”أ‡آ£plazas durasأ”أ‡أک de la â”œآ®poca. El aspecto de la plaza fue configurado asâ”œآ، en 1990. En 1996 se aâ”œâ–’adiâ”œâ”‚ al entorno una estatua de bronce, obra de Manuel Arcâ”œâ”‚n, representando a Eduardo Jimeno Correas, uno de los pioneros del cine espaâ”œâ–’ol.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65381000, -0.87818700, '0101000020E61000001CB7989F1B1AECBF1DE6CB0BB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207283017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207283017.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207283017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23070, 'Casa Tarâ”œآ،n 2007', 'Aspecto de la Casa Tarâ”œآ،n o del Canal Imperial, en la plaza de Santa Cruz 19 en 2007, antes de su restauraciâ”œâ”‚n en 2009. Fuente: Wikipedia.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65437700, -0.87882800, '0101000020E61000000DE4D9E55B1FECBF962023A0C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012098318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012098318.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012098318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23091, 'Plaza del Pilar 2000', 'Foto: Rogelio Allepuz, 8 de octubre de 2000. Despliegue de una gran bandera de Aragâ”œâ”‚n en la plaza del Pilar, el domingo 8 de octubre, al finalizar la manifestaciâ”œâ”‚n contra el Plan Hidrolâ”œâ”‚gico Nacional, que incluâ”œآ،a el trasvase del Ebro. Este vistoso ritual venâ”œآ،a practicâ”œأ­ndose, en el mismo entorno, desde 1993, con similares reivindicaciones. A la derecha, el Ayuntamiento luce engalanado por las Fiestas del Pilar, durante las que se celebrâ”œâ”‚ el acto, respaldado por el alcalde Josâ”œآ® Atarâ”œآ®s. Fuente: www.aparagon.org/fotoperiodistas/rogelio-allepuz/', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20343691156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20343691156.webp', 'https://www.flickr.com/photos/zaragozaantigua/20343691156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23157, 'Plaza del Pilar 2009', 'Dibujo de Lina Vila que representa una plaza del Pilar convertida en Venecia, merced a su inundaciâ”œâ”‚n. Al fondo, el Ayuntamiento y la Lonja. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65584400, -0.87769600, '0101000020E61000007E8FFAEB1516ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32427969364.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32427969364.webp', 'https://www.flickr.com/photos/zaragozaantigua/32427969364/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23181, 'Calle de San Braulio c.2000', 'Ilustraciâ”œâ”‚n centrada en el inmueble de la calle de San Braulio 5, construido en 1931 para sede de la Cooperativa Militar y Civil. Tras ser la sede del PSOE durante los aâ”œâ–’os noventa, fue remodelado, junto al nâ”œâ•‘mero 7 (que en la imagen luce un mural paisajâ”œآ،stico), para albergar el centro Joaquâ”œآ،n Roncal de la Funcaciâ”œâ”‚n CAI y Acciâ”œâ”‚n Social Catâ”œâ”‚lica, inaugurado en 2005. Fuente visual: "Centro Joaquâ”œآ،n Roncal en Zaragoza", La Cadiera, 2006.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65481800, -0.87946400, '0101000020E61000008C4CC0AF9124ECBF836A8313D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41410463091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41410463091.webp', 'https://www.flickr.com/photos/zaragozaantigua/41410463091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23206, 'Plaza del Pilar 2010', 'Foto: Toni Galâ”œأ­n. Marquesina en la plaza del Pilar, frente al Ayuntamiento, en mayo de 2010. Arriba, protesta de la Asociaciâ”œâ”‚n de Vecinos de La Madalena, por el deficiente arreglo del parque Bruil, con un millâ”œâ”‚n de euros procedentes del Plan E. Abajo, publicidad de la candidatura de Zaragoza a Capital Europea de la Cultura 2016. Competâ”œآ،a desde 2009 con otras 14 ciudades, que quedaron en seis en un segundo corte, con Segovia, Burgos, Câ”œâ”‚rdoba, Las Palmas de Gran Canaria y San Sebastiâ”œأ­n, que resultâ”œâ”‚ elegida en 2011. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65575600, -0.87818900, '0101000020E6100000499F56D11F1AECBFF01307D0EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32794799693.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32794799693.webp', 'https://www.flickr.com/photos/zaragozaantigua/32794799693/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23217, 'Plaza del Pilar 2016', 'Imagen lateral de la placa que recuerda a los 15 ediles republicanos y a los 30 trabajadores municipales asesinados por los sublevados en julio de 1936 contra la repâ”œâ•‘blica democrâ”œأ­tica de Espaâ”œâ–’a. 80 aâ”œâ–’os despuâ”œآ®s de los hechos, de ellos 37 tras la recuperaciâ”œâ”‚n de la democracia municipal, y estando al alcaldâ”œآ،a en manos de Zaragoza en Comâ”œâ•‘n, el viernes 30 de septiembre de 2016 fue inaugurado este memorial instalado en la esquina de la fachada principal del Ayuntamiento con la calle de Ximâ”œآ®nez de Embâ”œâ•‘n (a la derecha). En la imagen, obtenida con el punto de vista dirigido hacia el oeste de la plaza, la placa todavâ”œآ،a estâ”œأ­ cubierta por la tela que poco despuâ”œآ®s serâ”œآ،a retirada durante la inauguraciâ”œâ”‚n, en la que estuvieron presentes todos los grupos polâ”œآ،ticos con representaciâ”œâ”‚n municipal en aquella â”œآ®poca. La placa presenta un texto que dice: "A la memoria de los cargos electos y empleados municipales del Ayuntamiento de Zaragoza asesinados tras el golpe militar de julio de 1936 contra la legalidad constitucional de la Segunda Repâ”œâ•‘blica". Le sigue la relaciâ”œâ”‚n de nombres y apellidos de los 15 ediles, entre ellos cinco alcaldes pedâ”œأ­neos, y los 30 trabajadores municipales referidos. En la parte inferior, el escudo institucional del Ayuntamiento de Zaragoza.', 2016, 2016, 2016, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65585500, -0.87715700, '0101000020E61000009CA38E8EAB11ECBF84F57F0EF3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49980543982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49980543982.webp', 'https://www.flickr.com/photos/zaragozaantigua/49980543982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23246, 'Saraqusta 1118', 'Recreaciâ”œâ”‚n de Saraqusta y su entorno mâ”œأ­s inmediato en una vista aâ”œآ®rea sobre, en primer tâ”œآ®rmino, al-Jazirâ”œأ±/la Isla, donde Abderramâ”œأ­n III acampâ”œâ”‚ en 937 para asediar la ciudad, porque resulta complicado asediarla desde un enclave situado a 7 kilâ”œâ”‚metros en direcciâ”œâ”‚n noroeste, como algunos opinantes atribuyen al entorno del castillo de Miranda.. El de la izquierda serâ”œآ،a el brazo del râ”œآ،o que siglos despuâ”œآ®s, progresivamente desecado, darâ”œآ،a lugar a las Balsas de Ebro Viejo. Al otro lado de este brazo fluvial, el arrabal de -ad-Dabbajâ”œآ،n/de los Curtidores, luego de Altabâ”œأ­s, donde se bifurcan los caminos hacia Jaqath/Jaca, al norte, y Ifrâ”œأ­gâ”œأ±/Fraga, al este. Tras cruzar el nahr Ibruh/râ”œآ،o Ebro por al-Qantarath/el puente y rodeada por la muralla romana de piedra, recompuesta y reforzada varias veces, el perâ”œآ،metro de la madinâ”œأ±/ciudad de Saraqusta. Entrando por bâ”œأ­b al-Qantarath/Puerta de Alcâ”œأ­ntara o del puente, el -qasr qadim-/alcazar antiguo, la mezquita aljama y el barrio mozâ”œأ­rabe con la iglesia de Santa Marâ”œآ،a Virgen. Destacan a la izquierda la zona de bâ”œأ­b al-Qibla/puerta de la Qibla, actual Magdalena, junto al cementerio homâ”œâ”‚nimo, y a la derecha â”¬â”گal-kunna?/luego Torre Nueva, probable torre conmemorativa. En la esquina fluvial inferior destaca as-suddâ”œأ±/la Zuda, y bâ”œأ­b al-Qal''â”œأ±/Puerta Beikala o del Castillo, por la que se accedâ”œآ،a a al-Musâ”œأ­râ”œأ±/La Almozara. Aquâ”œآ، estaba uno de los tres cementerios de la ciudad y el mausoleo de los â”¬â”گBanâ”œâ•‌ Tujâ”œآ»b?, donde la actual torre de San Pablo, la mâ”œأ­s antigua de las torres conservadas. Tras la muralla de la medina estaban los arrabales, protegidos por una muralla de mardâ”œâ•‘mâ”œأ±-/tapial. Por la bâ”œأ­b Qala''â”œأ± Ayyâ”œâ•‘b-/puerta de Calatayud, luego denominada de Sancho, se llegaba a -qasr al-Ja''afariyyâ”œأ±-/palacio de La Aljaferâ”œآ،a. Paralela y entre los caminos a Tutilah/Tudela y Qal''ath Ayyâ”œâ•‘b/Calatayud, la assâ”œأ­qya al-Musâ”œأ­râ”œأ±/acequia de La Almozara. Otras puertas de los arrabales eran las de bâ”œأ­b Baltash/Baltax/luego del Carmen y -bâ”œأ­b al-Yahâ”œâ•‘dâ”œآ،n-/de los Judâ”œآ،os, luego Pue', 1118, 1118, 1118, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65431600, -0.87852000, '0101000020E6100000B0389CF9D51CECBFF19F6EA0C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49830304073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49830304073.webp', 'https://www.flickr.com/photos/zaragozaantigua/49830304073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
