INSERT INTO public.photos VALUES (23308, 'Calle de Alfonso I 1899', 'Interesante imagen capturada en la calle de Alfonso I a la altura del chaflanero desemboque de la calle de Prudencio (antigua de la Concepciâ”œâ”‚n), donde destaca el comercio de Tejidos Soteras. Detrâ”œأ­s de ella, la tambiâ”œآ®n chaflanera terminaciâ”œâ”‚n de la calle de la Manifestaciâ”œâ”‚n (antigua de la Platerâ”œآ،a). La estampa incluye una antropolâ”œâ”‚gica y plural galerâ”œآ،a de peatones, vendedora callejera ensillada (aprovechando la potencial clientela bajando hacia el templo del Pilar), câ”œأ­nido despavorido, y segâ”œâ•‘n nuestro experto en automâ”œâ”‚viles, monsieur Pierre Nodoyuna, posiblemente una "Voiturette" salida de los talleres de Alexis Vivinus en Bâ”œآ®lgica, o tal vez la versiâ”œâ”‚n de este modelo construida bajo licencia por Georges Richard en Francia. Fuente visual: foto Francisco Garzarâ”œأ­n, en Heraldo de Aragâ”œâ”‚n.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65569200, -0.87957100, '0101000020E61000000D52F0147225ECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29891168777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29891168777.webp', 'https://www.flickr.com/photos/zaragozaantigua/29891168777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23793, 'Templete 1987', '1987. Huelga universitaria. Los alumnos de Filosofâ”œآ،a, posando ante el templete de la Oficina de Turismo que se alzaba en la zona del Gobierno Civil de la plaza del Pilar. Arquitectura posmoderna, rememorando el templo romano cuya estructura quedâ”œâ”‚ destruida al construirse los garajes subterrâ”œأ­neos que estâ”œأ­n justo debajo. Fuente: Zaragozarebelde.org', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65575100, -0.87806900, '0101000020E6100000A034D4282419ECBFDFA815A6EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822216340.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822216340.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822216340/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
