INSERT INTO public.photos VALUES (23807, 'Fraga Iribarne 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 28/02/1965. "Visita del ministro de Informaciâ”œâ”‚n y Turismo Manuel Fraga Iribarne." Las fiestas del Pilar eran declaradas de "interâ”œآ®s turâ”œآ،stico nacional", como una iniciativa mâ”œأ­s de los planes de desarrollo impulsados por los tecnâ”œâ”‚cratas del Opus Dei. La orientaciâ”œâ”‚n del râ”œآ®gimen por el turismo incluyâ”œâ”‚ una especial atenciâ”œâ”‚n al "turismo religioso", mediante la creaciâ”œâ”‚n de instituciones turâ”œآ،sticas catâ”œâ”‚licas, un plan de apostolado para atender a turistas, y un cuerpo interdiocesano de capellanes del turismo que hablaran lenguas extranjeras. Ademâ”œأ­s, se ofrecerâ”œآ،an misas en lenguas foranas, peregrinaciones por grupos lingâ”œâ•‌â”œآ،sticos, y se establecerâ”œآ،an normas de "decencia" para el acceso de mujeres extranjeras a los templos (en verano, para evitar la lujuria). En la imagen, el ministro de Informaciâ”œâ”‚n y Turismo, Manuel Fraga Iribarne camino de rendir pleitesâ”œآ،a a la Virgen del Pilar. Luego negociarâ”œآ،a con el Arzobispado el dinero pâ”œâ•‘blico a transferir a las arcas del Cabildo para fomento del turismo religioso en la ciudad. Al fondo, la plaza de La Seo.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65572700, -0.87751100, '0101000020E61000000F2BDCF29114ECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15382864195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15382864195.webp', 'https://www.flickr.com/photos/zaragozaantigua/15382864195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23817, 'Casa de Torrellas 1844', '"Patio del Comercio". Saliendo de la calle de Santiago y llegando a la del Horno de la Yedra, se llegaba a la antigua casa de Torrellas, llamada luego del Comercio, si bien su propiedad era del marquâ”œآ®s de Ayerbe. Su patio en tres alturas soportadas sobre seis columnas era todo un monumento gâ”œâ”‚tico-plateresco sin igual en la ciudad, del que tampoco desmerecâ”œآ،an los artesonados de madera. Con la apertura de la nueva calle de Alfonso I, en la dâ”œآ®cada de los 60 del siglo XIX, la manzana en la que se asentaba esta joya fue arrasada, y se levantaron nuevas estructuras adaptadas al nuevo planeamiento de la zona. Algunos restos de este patio, descontextualizados, fueron reutilizados en el palacio que los marqueses de Ayerbe tenâ”œآ،an en la cercana calle del Pilar, cayendo por segunda vez cuando el edificio fue expropiado para construir el actual edificio del Ayuntamiento. Este segundo episodio de extinciâ”œâ”‚n terminâ”œâ”‚ con los restos de la casa de Torrellas. Fuente visual: "Recuerdos y Bellezas de Espaâ”œâ–’a. Obra destinada a dar a conocer sus monumentos, antigâ”œâ•‌edades y vistas pintorescas en lâ”œأ­minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompaâ”œâ–’adas de texto por P. Piferrer y J. M. Quadrado. Aragâ”œâ”‚n: Josâ”œآ® Marâ”œآ،a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65580700, -0.87892700, '0101000020E6100000D84812842B20ECBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18351577309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18351577309.webp', 'https://www.flickr.com/photos/zaragozaantigua/18351577309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
